/* ==================================================================== */
/* arena.c                                                            */
/* ==================================================================== */

#include "arena.h"
#include <stdlib.h>
#include <string.h>

#define ARENA_MAX_ALIGN 16

static size_t align_up(size_t val, size_t align) {
  return (val + align - 1) & ~(align - 1);
}

/*
 * Single allocation per chunk: the ixs_arena_chunk header lives at the
 * start of the malloc'd block, followed by the data region aligned to
 * ARENA_MAX_ALIGN.  One malloc, one free.  Returns NULL on overflow/OOM.
 */
static ixs_arena_chunk *chunk_new(size_t data_capacity) {
  size_t header_sz = align_up(sizeof(ixs_arena_chunk), ARENA_MAX_ALIGN);
  size_t total = header_sz + data_capacity;
  if (total < data_capacity)
    return NULL; /* overflow */
  ixs_arena_chunk *c = malloc(total);
  if (!c)
    return NULL;
  c->base = (char *)c + header_sz;
  c->used = 0;
  c->capacity = data_capacity;
  c->next = NULL;
  return c;
}

void ixs_arena_init(ixs_arena *a, size_t initial_size) {
  if (initial_size < IXS_ARENA_DEFAULT_SIZE)
    initial_size = IXS_ARENA_DEFAULT_SIZE;
  a->min_chunk = initial_size;
  a->current = NULL;
}

void ixs_arena_destroy(ixs_arena *a) {
  ixs_arena_chunk *c = a->current;
  while (c) {
    ixs_arena_chunk *next = c->next;
    free(c);
    c = next;
  }
  a->current = NULL;
}

void *ixs_arena_alloc(ixs_arena *a, size_t size, size_t align) {
  if (size == 0)
    size = 1;
  if (align == 0)
    align = 1;

  if (a->current) {
    size_t off = align_up(a->current->used, align);
    if (off <= a->current->capacity && size <= a->current->capacity - off) {
      a->current->used = off + size;
      return a->current->base + off;
    }
  }

  size_t prev = a->current ? a->current->capacity : 0;
  size_t want = size + align;
  if (want < size)
    return NULL; /* overflow */
  size_t cap = prev > 0 ? prev : a->min_chunk;

  while (cap < want) {
    size_t doubled = cap * 2;
    if (doubled <= cap)
      return NULL;
    cap = doubled;
  }

  ixs_arena_chunk *c = chunk_new(cap);
  if (!c)
    return NULL;
  c->next = a->current;
  a->current = c;

  c->used = size;
  return c->base;
}

char *ixs_arena_strdup(ixs_arena *a, const char *s, size_t len) {
  if (len == (size_t)-1)
    return NULL;
  char *p = ixs_arena_alloc(a, len + 1, 1);
  if (!p)
    return NULL;
  memcpy(p, s, len);
  p[len] = '\0';
  return p;
}

/* ==================================================================== */
/* bounds.c                                                           */
/* ==================================================================== */

#include "bounds.h"
#include <limits.h>
#include <string.h>

#ifndef INT64_MIN
#define INT64_MIN (-9223372036854775807LL - 1)
#endif
#ifndef INT64_MAX
#define INT64_MAX 9223372036854775807LL
#endif

void ixs_bounds_init(ixs_bounds *b) { memset(b, 0, sizeof(*b)); }

void ixs_bounds_destroy(ixs_bounds *b) { (void)b; }

static ixs_var_bound *find_var(ixs_bounds *b, const char *name) {
  size_t i;
  for (i = 0; i < b->nvars; i++) {
    if (strcmp(b->vars[i].name, name) == 0)
      return &b->vars[i];
  }
  return NULL;
}

static ixs_var_bound *get_or_create_var(ixs_bounds *b, const char *name) {
  ixs_var_bound *v = find_var(b, name);
  if (v)
    return v;
  if (b->nvars >= IXS_BOUNDS_MAX_VARS)
    return NULL;
  v = &b->vars[b->nvars++];
  v->name = name;
  v->iv.valid = true;
  v->iv.lo_p = INT64_MIN;
  v->iv.lo_q = 1;
  v->iv.hi_p = INT64_MAX;
  v->iv.hi_q = 1;
  v->divisor = 0;
  return v;
}

/* Record that sym is divisible by d (combine with lcm if existing). */
static void apply_divisor(ixs_bounds *b, const char *name, int64_t d) {
  ixs_var_bound *v = get_or_create_var(b, name);
  if (!v)
    return;
  if (v->divisor == 0) {
    v->divisor = d;
  } else {
    int64_t g = ixs_gcd(v->divisor, d);
    if (g > 0 && v->divisor <= INT64_MAX / (d / g))
      v->divisor = v->divisor / g * d;
  }
}

/* Recognize Mod(sym, const) == 0 as a divisibility assumption. */
static void extract_divisibility(ixs_bounds *b, ixs_node *a) {
  ixs_node *mod_node;

  if (a->tag != IXS_CMP || a->u.binary.cmp_op != IXS_CMP_EQ)
    return;

  if (a->u.binary.lhs->tag == IXS_MOD && ixs_node_is_zero(a->u.binary.rhs))
    mod_node = a->u.binary.lhs;
  else if (a->u.binary.rhs->tag == IXS_MOD && ixs_node_is_zero(a->u.binary.lhs))
    mod_node = a->u.binary.rhs;
  else
    return;

  ixs_node *dividend = mod_node->u.binary.lhs;
  ixs_node *modulus = mod_node->u.binary.rhs;
  if (dividend->tag == IXS_SYM && modulus->tag == IXS_INT &&
      modulus->u.ival > 0)
    apply_divisor(b, dividend->u.name, modulus->u.ival);
}

/*
 * Extract interval bounds and divisibility info from a comparison.
 * Patterns: sym >= 0, sym < N, Mod(sym, d) == 0, etc.
 */
void ixs_bounds_add_assumption(ixs_bounds *b, ixs_node *a) {
  if (a->tag != IXS_CMP)
    return;

  extract_divisibility(b, a);

  ixs_node *lhs = a->u.binary.lhs;
  ixs_node *rhs = a->u.binary.rhs;
  ixs_cmp_op op = a->u.binary.cmp_op;
  ixs_var_bound *v;

  /* Pattern: sym op const */
  if (lhs->tag == IXS_SYM && ixs_node_is_const(rhs)) {
    int64_t rp, rq;
    ixs_node_get_rat(rhs, &rp, &rq);
    v = get_or_create_var(b, lhs->u.name);
    if (!v)
      return;
    switch (op) {
    case IXS_CMP_GE:
      if (ixs_rat_cmp(rp, rq, v->iv.lo_p, v->iv.lo_q) > 0) {
        v->iv.lo_p = rp;
        v->iv.lo_q = rq;
      }
      break;
    case IXS_CMP_GT:
      /* sym > c  →  sym >= c + 1 (integer context) */
      if (rq == 1) {
        int64_t lo = rp + 1;
        if (ixs_rat_cmp(lo, 1, v->iv.lo_p, v->iv.lo_q) > 0) {
          v->iv.lo_p = lo;
          v->iv.lo_q = 1;
        }
      }
      break;
    case IXS_CMP_LE:
      if (ixs_rat_cmp(rp, rq, v->iv.hi_p, v->iv.hi_q) < 0) {
        v->iv.hi_p = rp;
        v->iv.hi_q = rq;
      }
      break;
    case IXS_CMP_LT:
      if (rq == 1) {
        int64_t hi = rp - 1;
        if (ixs_rat_cmp(hi, 1, v->iv.hi_p, v->iv.hi_q) < 0) {
          v->iv.hi_p = hi;
          v->iv.hi_q = 1;
        }
      }
      break;
    case IXS_CMP_EQ:
      v->iv.lo_p = rp;
      v->iv.lo_q = rq;
      v->iv.hi_p = rp;
      v->iv.hi_q = rq;
      break;
    case IXS_CMP_NE:
      break;
    }
    return;
  }

  /* Pattern: const op sym (flip) */
  if (rhs->tag == IXS_SYM && ixs_node_is_const(lhs)) {
    int64_t lp, lq;
    ixs_node_get_rat(lhs, &lp, &lq);
    v = get_or_create_var(b, rhs->u.name);
    if (!v)
      return;
    switch (op) {
    case IXS_CMP_GE: /* const >= sym → sym <= const */
      if (ixs_rat_cmp(lp, lq, v->iv.hi_p, v->iv.hi_q) < 0) {
        v->iv.hi_p = lp;
        v->iv.hi_q = lq;
      }
      break;
    case IXS_CMP_GT:
      if (lq == 1) {
        int64_t hi = lp - 1;
        if (ixs_rat_cmp(hi, 1, v->iv.hi_p, v->iv.hi_q) < 0) {
          v->iv.hi_p = hi;
          v->iv.hi_q = 1;
        }
      }
      break;
    case IXS_CMP_LE:
      if (ixs_rat_cmp(lp, lq, v->iv.lo_p, v->iv.lo_q) > 0) {
        v->iv.lo_p = lp;
        v->iv.lo_q = lq;
      }
      break;
    case IXS_CMP_LT:
      if (lq == 1) {
        int64_t lo = lp + 1;
        if (ixs_rat_cmp(lo, 1, v->iv.lo_p, v->iv.lo_q) > 0) {
          v->iv.lo_p = lo;
          v->iv.lo_q = 1;
        }
      }
      break;
    case IXS_CMP_EQ:
      v->iv.lo_p = lp;
      v->iv.lo_q = lq;
      v->iv.hi_p = lp;
      v->iv.hi_q = lq;
      break;
    case IXS_CMP_NE:
      break;
    }
    return;
  }

  /*
   * Pattern: (sym - const) cmp 0  (from comparison normalization).
   * The lhs is an ADD with one SYM term and a constant offset.
   */
  if (ixs_node_is_zero(rhs) && lhs->tag == IXS_ADD && lhs->u.add.nterms == 1 &&
      lhs->u.add.terms[0].term->tag == IXS_SYM) {
    int64_t tp, tq, kp, kq;
    ixs_node_get_rat(lhs->u.add.terms[0].coeff, &tp, &tq);
    ixs_node_get_rat(lhs->u.add.coeff, &kp, &kq);

    /* We have: tp/tq * sym + kp/kq  OP  0 */
    if (tp == 1 && tq == 1) {
      /* sym + k OP 0  →  sym OP -k */
      int64_t rp2, rq2;
      if (!ixs_rat_neg(kp, kq, &rp2, &rq2))
        return;
      v = get_or_create_var(b, lhs->u.add.terms[0].term->u.name);
      if (!v)
        return;
      switch (op) {
      case IXS_CMP_GE:
        if (ixs_rat_cmp(rp2, rq2, v->iv.lo_p, v->iv.lo_q) > 0) {
          v->iv.lo_p = rp2;
          v->iv.lo_q = rq2;
        }
        break;
      case IXS_CMP_GT:
        if (rq2 == 1) {
          int64_t lo = rp2 + 1;
          if (ixs_rat_cmp(lo, 1, v->iv.lo_p, v->iv.lo_q) > 0) {
            v->iv.lo_p = lo;
            v->iv.lo_q = 1;
          }
        }
        break;
      case IXS_CMP_LE:
        if (ixs_rat_cmp(rp2, rq2, v->iv.hi_p, v->iv.hi_q) < 0) {
          v->iv.hi_p = rp2;
          v->iv.hi_q = rq2;
        }
        break;
      case IXS_CMP_LT:
        if (rq2 == 1) {
          int64_t hi = rp2 - 1;
          if (ixs_rat_cmp(hi, 1, v->iv.hi_p, v->iv.hi_q) < 0) {
            v->iv.hi_p = hi;
            v->iv.hi_q = 1;
          }
        }
        break;
      default:
        break;
      }
    }
  }
}

/* ------------------------------------------------------------------ */
/*  Interval propagation                                              */
/* ------------------------------------------------------------------ */

static ixs_interval iv_add(ixs_interval a, ixs_interval b) {
  ixs_interval r;
  if (!a.valid || !b.valid)
    return ixs_interval_unknown();
  r.valid = true;
  if (!ixs_rat_add(a.lo_p, a.lo_q, b.lo_p, b.lo_q, &r.lo_p, &r.lo_q))
    return ixs_interval_unknown();
  if (!ixs_rat_add(a.hi_p, a.hi_q, b.hi_p, b.hi_q, &r.hi_p, &r.hi_q))
    return ixs_interval_unknown();
  return r;
}

static ixs_interval iv_mul_const(ixs_interval a, int64_t cp, int64_t cq) {
  ixs_interval r;
  if (!a.valid)
    return ixs_interval_unknown();
  r.valid = true;
  if (!ixs_rat_mul(a.lo_p, a.lo_q, cp, cq, &r.lo_p, &r.lo_q) ||
      !ixs_rat_mul(a.hi_p, a.hi_q, cp, cq, &r.hi_p, &r.hi_q))
    return ixs_interval_unknown();
  /* If multiplier is negative, swap lo and hi. */
  if (ixs_rat_is_neg(cp)) {
    int64_t tmp_p = r.lo_p, tmp_q = r.lo_q;
    r.lo_p = r.hi_p;
    r.lo_q = r.hi_q;
    r.hi_p = tmp_p;
    r.hi_q = tmp_q;
  }
  return r;
}

ixs_interval ixs_bounds_get(ixs_bounds *b, ixs_node *expr) {
  uint32_t i;
  if (!expr)
    return ixs_interval_unknown();

  switch (expr->tag) {
  case IXS_INT:
    return ixs_interval_exact(expr->u.ival, 1);
  case IXS_RAT:
    return ixs_interval_exact(expr->u.rat.p, expr->u.rat.q);
  case IXS_SYM: {
    ixs_var_bound *v = find_var(b, expr->u.name);
    if (v)
      return v->iv;
    return ixs_interval_unknown();
  }
  case IXS_ADD: {
    /* Start with constant term. */
    ixs_interval result = ixs_bounds_get(b, expr->u.add.coeff);
    for (i = 0; i < expr->u.add.nterms; i++) {
      ixs_interval ti = ixs_bounds_get(b, expr->u.add.terms[i].term);
      int64_t cp, cq;
      ixs_node_get_rat(expr->u.add.terms[i].coeff, &cp, &cq);
      ixs_interval scaled = iv_mul_const(ti, cp, cq);
      result = iv_add(result, scaled);
    }
    return result;
  }
  case IXS_MUL: {
    /* Only handle simple cases: const * single factor. */
    if (expr->u.mul.nfactors == 1 && expr->u.mul.factors[0].exp == 1) {
      int64_t cp, cq;
      ixs_node_get_rat(expr->u.mul.coeff, &cp, &cq);
      ixs_interval fi = ixs_bounds_get(b, expr->u.mul.factors[0].base);
      return iv_mul_const(fi, cp, cq);
    }
    return ixs_interval_unknown();
  }
  case IXS_MOD: {
    /* Mod(x, m) ∈ [0, m-1] only when x is integer-valued and m is a
     * positive integer.  For non-integer dividends the range is the
     * half-open [0, m) which we cannot represent tightly. */
    ixs_node *m = expr->u.binary.rhs;
    if (m->tag == IXS_INT && m->u.ival > 0) {
      ixs_interval pi = ixs_bounds_get(b, expr->u.binary.lhs);
      if (pi.valid && pi.lo_q == 1 && pi.hi_q == 1 && pi.lo_p >= 0 &&
          pi.hi_p < m->u.ival)
        return pi;
      if (ixs_node_is_integer_valued(expr->u.binary.lhs))
        return ixs_interval_range(0, 1, m->u.ival - 1, 1);
    }
    return ixs_interval_unknown();
  }
  case IXS_FLOOR: {
    ixs_interval ai = ixs_bounds_get(b, expr->u.unary.arg);
    if (!ai.valid)
      return ixs_interval_unknown();
    return ixs_interval_range(ixs_rat_floor(ai.lo_p, ai.lo_q), 1,
                              ixs_rat_floor(ai.hi_p, ai.hi_q), 1);
  }
  case IXS_CEIL: {
    ixs_interval ai = ixs_bounds_get(b, expr->u.unary.arg);
    if (!ai.valid)
      return ixs_interval_unknown();
    return ixs_interval_range(ixs_rat_ceil(ai.lo_p, ai.lo_q), 1,
                              ixs_rat_ceil(ai.hi_p, ai.hi_q), 1);
  }
  case IXS_MAX: {
    ixs_interval li = ixs_bounds_get(b, expr->u.binary.lhs);
    ixs_interval ri = ixs_bounds_get(b, expr->u.binary.rhs);
    if (!li.valid || !ri.valid)
      return ixs_interval_unknown();
    ixs_interval result;
    result.valid = true;
    /* max(lo_l, lo_r) <= max(l, r) <= max(hi_l, hi_r) */
    result.lo_p = ixs_rat_cmp(li.lo_p, li.lo_q, ri.lo_p, ri.lo_q) >= 0
                      ? li.lo_p
                      : ri.lo_p;
    result.lo_q = ixs_rat_cmp(li.lo_p, li.lo_q, ri.lo_p, ri.lo_q) >= 0
                      ? li.lo_q
                      : ri.lo_q;
    result.hi_p = ixs_rat_cmp(li.hi_p, li.hi_q, ri.hi_p, ri.hi_q) >= 0
                      ? li.hi_p
                      : ri.hi_p;
    result.hi_q = ixs_rat_cmp(li.hi_p, li.hi_q, ri.hi_p, ri.hi_q) >= 0
                      ? li.hi_q
                      : ri.hi_q;
    return result;
  }
  case IXS_MIN: {
    ixs_interval li = ixs_bounds_get(b, expr->u.binary.lhs);
    ixs_interval ri = ixs_bounds_get(b, expr->u.binary.rhs);
    if (!li.valid || !ri.valid)
      return ixs_interval_unknown();
    ixs_interval result;
    result.valid = true;
    result.lo_p = ixs_rat_cmp(li.lo_p, li.lo_q, ri.lo_p, ri.lo_q) <= 0
                      ? li.lo_p
                      : ri.lo_p;
    result.lo_q = ixs_rat_cmp(li.lo_p, li.lo_q, ri.lo_p, ri.lo_q) <= 0
                      ? li.lo_q
                      : ri.lo_q;
    result.hi_p = ixs_rat_cmp(li.hi_p, li.hi_q, ri.hi_p, ri.hi_q) <= 0
                      ? li.hi_p
                      : ri.hi_p;
    result.hi_q = ixs_rat_cmp(li.hi_p, li.hi_q, ri.hi_p, ri.hi_q) <= 0
                      ? li.hi_q
                      : ri.hi_q;
    return result;
  }
  default:
    return ixs_interval_unknown();
  }
}

int64_t ixs_bounds_get_divisor(ixs_bounds *b, const char *name) {
  ixs_var_bound *v = find_var(b, name);
  return v ? v->divisor : 0;
}

/* ==================================================================== */
/* ctx.c                                                              */
/* ==================================================================== */

#include "node.h"
#include "parser.h"
#include "print.h"
#include "simplify.h"
#include <stdlib.h>
#include <string.h>

/* ------------------------------------------------------------------ */
/*  Singleton creation                                                */
/* ------------------------------------------------------------------ */

static ixs_node *make_singleton(ixs_ctx *ctx, ixs_tag tag, uint32_t seed) {
  ixs_node *n = ixs_arena_alloc(&ctx->arena, sizeof(ixs_node), sizeof(void *));
  if (!n)
    return NULL;
  memset(n, 0, sizeof(*n));
  n->tag = tag;
  n->hash = (uint32_t)tag * 2654435761u;
  n->hash ^= seed;
  n->hash *= 0x9e3779b9u;
  /* Insert into hash table. */
  return ixs_htab_intern(ctx, n);
}

/* ------------------------------------------------------------------ */
/*  Context lifecycle                                                 */
/* ------------------------------------------------------------------ */

ixs_ctx *ixs_ctx_create(void) {
  ixs_ctx *ctx = calloc(1, sizeof(ixs_ctx));
  if (!ctx)
    return NULL;

  ixs_arena_init(&ctx->arena, IXS_ARENA_DEFAULT_SIZE);

  if (!ixs_htab_init(ctx)) {
    free(ctx);
    return NULL;
  }

  /* Create singletons. */
  ctx->sentinel_error = make_singleton(ctx, IXS_ERROR, 0xDEAD);
  ctx->sentinel_parse_error = make_singleton(ctx, IXS_PARSE_ERROR, 0xBEEF);
  ctx->node_true = make_singleton(ctx, IXS_TRUE, 1);
  ctx->node_false = make_singleton(ctx, IXS_FALSE, 0);

  if (!ctx->sentinel_error || !ctx->sentinel_parse_error || !ctx->node_true ||
      !ctx->node_false) {
    ixs_ctx_destroy(ctx);
    return NULL;
  }

  ctx->node_zero = ixs_node_int(ctx, 0);
  ctx->node_one = ixs_node_int(ctx, 1);

  if (!ctx->node_zero || !ctx->node_one) {
    ixs_ctx_destroy(ctx);
    return NULL;
  }

  return ctx;
}

void ixs_ctx_destroy(ixs_ctx *ctx) {
  if (!ctx)
    return;
  ixs_htab_destroy(ctx);
  ixs_arena_destroy(&ctx->arena);
  free((void *)ctx->errors);
  free(ctx);
}

/* ------------------------------------------------------------------ */
/*  Error list                                                        */
/* ------------------------------------------------------------------ */

size_t ixs_ctx_nerrors(ixs_ctx *ctx) { return ctx->nerrors; }

const char *ixs_ctx_error(ixs_ctx *ctx, size_t index) {
  if (index >= ctx->nerrors)
    return NULL;
  return ctx->errors[index];
}

void ixs_ctx_clear_errors(ixs_ctx *ctx) { ctx->nerrors = 0; }

/* ------------------------------------------------------------------ */
/*  Sentinel checks                                                   */
/* ------------------------------------------------------------------ */

bool ixs_is_error(ixs_node *node) {
  return node && (node->tag == IXS_ERROR || node->tag == IXS_PARSE_ERROR);
}

bool ixs_is_parse_error(ixs_node *node) {
  return node && node->tag == IXS_PARSE_ERROR;
}

bool ixs_is_domain_error(ixs_node *node) {
  return node && node->tag == IXS_ERROR;
}

/* ------------------------------------------------------------------ */
/*  Constructors (delegate to simplify.c)                             */
/* ------------------------------------------------------------------ */

ixs_node *ixs_int(ixs_ctx *ctx, int64_t val) { return ixs_node_int(ctx, val); }

ixs_node *ixs_rat(ixs_ctx *ctx, int64_t p, int64_t q) {
  if (q == 0) {
    ixs_ctx_push_error(ctx, "ixs_rat: denominator is zero");
    return ctx->sentinel_error;
  }
  int64_t rp, rq;
  if (!ixs_rat_normalize(p, q, &rp, &rq)) {
    ixs_ctx_push_error(ctx, "ixs_rat: rational overflow");
    return ctx->sentinel_error;
  }
  return ixs_node_rat(ctx, rp, rq);
}

ixs_node *ixs_sym(ixs_ctx *ctx, const char *name) {
  return ixs_node_sym(ctx, name, strlen(name));
}

ixs_node *ixs_add(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  return simp_add(ctx, a, b);
}

ixs_node *ixs_mul(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  return simp_mul(ctx, a, b);
}

ixs_node *ixs_neg(ixs_ctx *ctx, ixs_node *a) { return simp_neg(ctx, a); }

ixs_node *ixs_sub(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  return simp_sub(ctx, a, b);
}

