/* ------------------------------------------------------------------ */
/*  Simplification                                                    */
/* ------------------------------------------------------------------ */

ixs_node *ixs_simplify(ixs_ctx *ctx, ixs_node *expr,
                       ixs_node *const *assumptions, size_t n_assumptions) {
  return simp_simplify(ctx, expr, assumptions, n_assumptions);
}

void ixs_simplify_batch(ixs_ctx *ctx, ixs_node **exprs, size_t n,
                        ixs_node *const *assumptions, size_t n_assumptions) {
  size_t i;
  for (i = 0; i < n; i++) {
    if (!exprs[i] || ixs_node_is_sentinel(exprs[i]))
      continue;
    exprs[i] = simp_simplify(ctx, exprs[i], assumptions, n_assumptions);
    if (!exprs[i]) {
      /* OOM: null out everything. */
      size_t j;
      for (j = 0; j < n; j++)
        exprs[j] = NULL;
      return;
    }
  }
}

