#include "node.h"
#include <stdarg.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* ------------------------------------------------------------------ */
/*  Hashing                                                           */
/* ------------------------------------------------------------------ */

static uint32_t hash_mix(uint32_t h, uint32_t v) {
  h ^= v;
  h *= 0x9e3779b9u;
  h ^= h >> 16;
  return h;
}

static uint32_t hash_i64(int64_t v) {
  uint64_t u = (uint64_t)v;
  return (uint32_t)(u ^ (u >> 32));
}

static uint32_t hash_str(const char *s, size_t len) {
  uint32_t h = 5381;
  size_t i;
  for (i = 0; i < len; i++)
    h = ((h << 5) + h) ^ (unsigned char)s[i];
  return h;
}

static uint32_t compute_hash(const ixs_node *n) {
  uint32_t h = (uint32_t)n->tag * 2654435761u;
  switch (n->tag) {
  case IXS_INT:
    h = hash_mix(h, hash_i64(n->u.ival));
    break;
  case IXS_RAT:
    h = hash_mix(h, hash_i64(n->u.rat.p));
    h = hash_mix(h, hash_i64(n->u.rat.q));
    break;
  case IXS_SYM:
    h = hash_mix(h, hash_str(n->u.name, strlen(n->u.name)));
    break;
  case IXS_ADD: {
    h = hash_mix(h, n->u.add.coeff->hash);
    uint32_t i;
    for (i = 0; i < n->u.add.nterms; i++) {
      h = hash_mix(h, n->u.add.terms[i].term->hash);
      h = hash_mix(h, n->u.add.terms[i].coeff->hash);
    }
    break;
  }
  case IXS_MUL: {
    h = hash_mix(h, n->u.mul.coeff->hash);
    uint32_t i;
    for (i = 0; i < n->u.mul.nfactors; i++) {
      h = hash_mix(h, n->u.mul.factors[i].base->hash);
      h = hash_mix(h, (uint32_t)n->u.mul.factors[i].exp);
    }
    break;
  }
  case IXS_FLOOR:
  case IXS_CEIL:
    h = hash_mix(h, n->u.unary.arg->hash);
    break;
  case IXS_MOD:
  case IXS_MAX:
  case IXS_MIN:
  case IXS_XOR:
    h = hash_mix(h, n->u.binary.lhs->hash);
    h = hash_mix(h, n->u.binary.rhs->hash);
    break;
  case IXS_CMP:
    h = hash_mix(h, n->u.binary.lhs->hash);
    h = hash_mix(h, n->u.binary.rhs->hash);
    h = hash_mix(h, (uint32_t)n->u.binary.cmp_op);
    break;
  case IXS_PIECEWISE: {
    uint32_t i;
    for (i = 0; i < n->u.pw.ncases; i++) {
      h = hash_mix(h, n->u.pw.cases[i].value->hash);
      h = hash_mix(h, n->u.pw.cases[i].cond->hash);
    }
    break;
  }
  case IXS_AND:
  case IXS_OR: {
    uint32_t i;
    for (i = 0; i < n->u.logic.nargs; i++)
      h = hash_mix(h, n->u.logic.args[i]->hash);
    break;
  }
  case IXS_NOT:
    h = hash_mix(h, n->u.unary_bool.arg->hash);
    break;
  case IXS_TRUE:
    h = hash_mix(h, 1);
    break;
  case IXS_FALSE:
    h = hash_mix(h, 0);
    break;
  case IXS_ERROR:
    h = hash_mix(h, 0xDEAD);
    break;
  case IXS_PARSE_ERROR:
    h = hash_mix(h, 0xBEEF);
    break;
  }
  return h;
}

/* ------------------------------------------------------------------ */
/*  Node equality (structural)                                        */
/* ------------------------------------------------------------------ */

bool ixs_node_equal(const ixs_node *a, const ixs_node *b) {
  uint32_t i;
  if (a == b)
    return true;
  if (a->tag != b->tag)
    return false;
  switch (a->tag) {
  case IXS_INT:
    return a->u.ival == b->u.ival;
  case IXS_RAT:
    return a->u.rat.p == b->u.rat.p && a->u.rat.q == b->u.rat.q;
  case IXS_SYM:
    return strcmp(a->u.name, b->u.name) == 0;
  case IXS_ADD:
    if (a->u.add.coeff != b->u.add.coeff)
      return false;
    if (a->u.add.nterms != b->u.add.nterms)
      return false;
    for (i = 0; i < a->u.add.nterms; i++) {
      if (a->u.add.terms[i].term != b->u.add.terms[i].term)
        return false;
      if (a->u.add.terms[i].coeff != b->u.add.terms[i].coeff)
        return false;
    }
    return true;
  case IXS_MUL:
    if (a->u.mul.coeff != b->u.mul.coeff)
      return false;
    if (a->u.mul.nfactors != b->u.mul.nfactors)
      return false;
    for (i = 0; i < a->u.mul.nfactors; i++) {
      if (a->u.mul.factors[i].base != b->u.mul.factors[i].base)
        return false;
      if (a->u.mul.factors[i].exp != b->u.mul.factors[i].exp)
        return false;
    }
    return true;
  case IXS_FLOOR:
  case IXS_CEIL:
    return a->u.unary.arg == b->u.unary.arg;
  case IXS_CMP:
    return a->u.binary.lhs == b->u.binary.lhs &&
           a->u.binary.rhs == b->u.binary.rhs &&
           a->u.binary.cmp_op == b->u.binary.cmp_op;
  case IXS_MOD:
  case IXS_MAX:
  case IXS_MIN:
  case IXS_XOR:
    return a->u.binary.lhs == b->u.binary.lhs &&
           a->u.binary.rhs == b->u.binary.rhs;
  case IXS_PIECEWISE:
    if (a->u.pw.ncases != b->u.pw.ncases)
      return false;
    for (i = 0; i < a->u.pw.ncases; i++) {
      if (a->u.pw.cases[i].value != b->u.pw.cases[i].value)
        return false;
      if (a->u.pw.cases[i].cond != b->u.pw.cases[i].cond)
        return false;
    }
    return true;
  case IXS_AND:
  case IXS_OR:
    if (a->u.logic.nargs != b->u.logic.nargs)
      return false;
    for (i = 0; i < a->u.logic.nargs; i++)
      if (a->u.logic.args[i] != b->u.logic.args[i])
        return false;
    return true;
  case IXS_NOT:
    return a->u.unary_bool.arg == b->u.unary_bool.arg;
  case IXS_TRUE:
  case IXS_FALSE:
  case IXS_ERROR:
  case IXS_PARSE_ERROR:
    return true;
  }
  return false;
}

/* ------------------------------------------------------------------ */
/*  Node comparison (total order)                                     */
/* ------------------------------------------------------------------ */

/*
 * Total order on nodes for canonical sorting.  Fast path: hash-consed
 * nodes with identical structure are pointer-equal, caught immediately.
 * Next: compare by precomputed structural hash (O(1), deterministic).
 * Recursive fallback fires only on the rare 32-bit hash collision.
 */
int ixs_node_cmp(const ixs_node *a, const ixs_node *b) {
  uint32_t i;
  int c;
  if (a == b)
    return 0;
  if (a->hash != b->hash)
    return a->hash < b->hash ? -1 : 1;
  if ((int)a->tag != (int)b->tag)
    return (int)a->tag < (int)b->tag ? -1 : 1;

  switch (a->tag) {
  case IXS_INT:
    if (a->u.ival < b->u.ival)
      return -1;
    if (a->u.ival > b->u.ival)
      return 1;
    return 0;
  case IXS_RAT:
    return ixs_rat_cmp(a->u.rat.p, a->u.rat.q, b->u.rat.p, b->u.rat.q);
  case IXS_SYM:
    return strcmp(a->u.name, b->u.name);
  case IXS_ADD:
    c = ixs_node_cmp(a->u.add.coeff, b->u.add.coeff);
    if (c)
      return c;
    if (a->u.add.nterms != b->u.add.nterms)
      return a->u.add.nterms < b->u.add.nterms ? -1 : 1;
    for (i = 0; i < a->u.add.nterms; i++) {
      c = ixs_node_cmp(a->u.add.terms[i].term, b->u.add.terms[i].term);
      if (c)
        return c;
      c = ixs_node_cmp(a->u.add.terms[i].coeff, b->u.add.terms[i].coeff);
      if (c)
        return c;
    }
    return 0;
  case IXS_MUL:
    c = ixs_node_cmp(a->u.mul.coeff, b->u.mul.coeff);
    if (c)
      return c;
    if (a->u.mul.nfactors != b->u.mul.nfactors)
      return a->u.mul.nfactors < b->u.mul.nfactors ? -1 : 1;
    for (i = 0; i < a->u.mul.nfactors; i++) {
      c = ixs_node_cmp(a->u.mul.factors[i].base, b->u.mul.factors[i].base);
      if (c)
        return c;
      if (a->u.mul.factors[i].exp != b->u.mul.factors[i].exp)
        return a->u.mul.factors[i].exp < b->u.mul.factors[i].exp ? -1 : 1;
    }
    return 0;
  case IXS_FLOOR:
  case IXS_CEIL:
    return ixs_node_cmp(a->u.unary.arg, b->u.unary.arg);
  case IXS_CMP:
    if (a->u.binary.cmp_op != b->u.binary.cmp_op)
      return (int)a->u.binary.cmp_op < (int)b->u.binary.cmp_op ? -1 : 1;
    /* fallthrough */
  case IXS_MOD:
  case IXS_MAX:
  case IXS_MIN:
  case IXS_XOR:
    c = ixs_node_cmp(a->u.binary.lhs, b->u.binary.lhs);
    if (c)
      return c;
    return ixs_node_cmp(a->u.binary.rhs, b->u.binary.rhs);
  case IXS_PIECEWISE:
    if (a->u.pw.ncases != b->u.pw.ncases)
      return a->u.pw.ncases < b->u.pw.ncases ? -1 : 1;
    for (i = 0; i < a->u.pw.ncases; i++) {
      c = ixs_node_cmp(a->u.pw.cases[i].value, b->u.pw.cases[i].value);
      if (c)
        return c;
      c = ixs_node_cmp(a->u.pw.cases[i].cond, b->u.pw.cases[i].cond);
      if (c)
        return c;
    }
    return 0;
  case IXS_AND:
  case IXS_OR:
    if (a->u.logic.nargs != b->u.logic.nargs)
      return a->u.logic.nargs < b->u.logic.nargs ? -1 : 1;
    for (i = 0; i < a->u.logic.nargs; i++) {
      c = ixs_node_cmp(a->u.logic.args[i], b->u.logic.args[i]);
      if (c)
        return c;
    }
    return 0;
  case IXS_NOT:
    return ixs_node_cmp(a->u.unary_bool.arg, b->u.unary_bool.arg);
  case IXS_TRUE:
  case IXS_FALSE:
  case IXS_ERROR:
  case IXS_PARSE_ERROR:
    return 0;
  }
  return 0;
}

/* ------------------------------------------------------------------ */
/*  Hash-consing table                                                */
/* ------------------------------------------------------------------ */

bool ixs_htab_init(ixs_ctx *ctx) {
  ctx->htab_cap = IXS_HTAB_INIT_CAP;
  ctx->htab_used = 0;
  ctx->htab = calloc(ctx->htab_cap, sizeof(ixs_node *));
  return ctx->htab != NULL;
}

void ixs_htab_destroy(ixs_ctx *ctx) {
  free(ctx->htab);
  ctx->htab = NULL;
}

static bool htab_rehash(ixs_ctx *ctx) {
  size_t new_cap = ctx->htab_cap * 2;
  if (new_cap < ctx->htab_cap)
    return false;

  ixs_node **new_buckets = calloc(new_cap, sizeof(ixs_node *));
  if (!new_buckets)
    return false;

  size_t mask = new_cap - 1;
  size_t i;
  for (i = 0; i < ctx->htab_cap; i++) {
    ixs_node *n = ctx->htab[i];
    if (!n)
      continue;
    size_t idx = n->hash & mask;
    while (new_buckets[idx])
      idx = (idx + 1) & mask;
    new_buckets[idx] = n;
  }

  free(ctx->htab);
  ctx->htab = new_buckets;
  ctx->htab_cap = new_cap;
  return true;
}

ixs_node *ixs_htab_intern(ixs_ctx *ctx, ixs_node *node) {
  size_t mask = ctx->htab_cap - 1;
  size_t idx = node->hash & mask;

  for (;;) {
    ixs_node *slot = ctx->htab[idx];
    if (!slot) {
      ctx->htab[idx] = node;
      ctx->htab_used++;
      if (ctx->htab_used * IXS_HTAB_LOAD_DEN >
          ctx->htab_cap * IXS_HTAB_LOAD_NUM) {
        if (!htab_rehash(ctx))
          return NULL;
      }
      return node;
    }
    if (slot->hash == node->hash && ixs_node_equal(slot, node))
      return slot;
    idx = (idx + 1) & mask;
  }
}

/* ------------------------------------------------------------------ */
/*  Arena allocation helpers                                          */
/* ------------------------------------------------------------------ */

static ixs_node *alloc_node(ixs_ctx *ctx) {
  ixs_node *n = ixs_arena_alloc(&ctx->arena, sizeof(ixs_node), sizeof(void *));
  if (n)
    memset(n, 0, sizeof(*n));
  return n;
}

/* ------------------------------------------------------------------ */
/*  Raw node constructors                                             */
/* ------------------------------------------------------------------ */

ixs_node *ixs_node_int(ixs_ctx *ctx, int64_t val) {
  ixs_node tmp;
  memset(&tmp, 0, sizeof(tmp));
  tmp.tag = IXS_INT;
  tmp.u.ival = val;
  tmp.hash = compute_hash(&tmp);

  /* Check hash table first to avoid redundant arena alloc. */
  size_t mask = ctx->htab_cap - 1;
  size_t idx = tmp.hash & mask;
  for (;;) {
    ixs_node *slot = ctx->htab[idx];
    if (!slot)
      break;
    if (slot->hash == tmp.hash && ixs_node_equal(slot, &tmp))
      return slot;
    idx = (idx + 1) & mask;
  }

  ixs_node *n = alloc_node(ctx);
  if (!n)
    return NULL;
  *n = tmp;
  return ixs_htab_intern(ctx, n);
}

ixs_node *ixs_node_rat(ixs_ctx *ctx, int64_t p, int64_t q) {
  if (q == 1)
    return ixs_node_int(ctx, p);

  ixs_node *n = alloc_node(ctx);
  if (!n)
    return NULL;
  n->tag = IXS_RAT;
  n->u.rat.p = p;
  n->u.rat.q = q;
  n->hash = compute_hash(n);
  return ixs_htab_intern(ctx, n);
}

ixs_node *ixs_node_sym(ixs_ctx *ctx, const char *name, size_t len) {
  uint32_t sym_hash;
  ixs_node *n;
  char *interned;

  /* Compute hash from the bounded slice — name may not be NUL-terminated. */
  sym_hash = (uint32_t)IXS_SYM * 2654435761u;
  sym_hash = hash_mix(sym_hash, hash_str(name, len));

  {
    size_t mask = ctx->htab_cap - 1;
    size_t idx = sym_hash & mask;
    for (;;) {
      ixs_node *slot = ctx->htab[idx];
      if (!slot)
        break;
      if (slot->hash == sym_hash && slot->tag == IXS_SYM &&
          strlen(slot->u.name) == len && memcmp(slot->u.name, name, len) == 0)
        return slot;
      idx = (idx + 1) & mask;
    }
  }

  interned = ixs_arena_strdup(&ctx->arena, name, len);
  if (!interned)
    return NULL;

  n = alloc_node(ctx);
  if (!n)
    return NULL;
  n->tag = IXS_SYM;
  n->u.name = interned;
  n->hash = sym_hash;
  return ixs_htab_intern(ctx, n);
}

ixs_node *ixs_node_add(ixs_ctx *ctx, ixs_node *coeff, uint32_t nterms,
                       ixs_addterm *terms) {
  ixs_addterm *a = ixs_arena_alloc(&ctx->arena, nterms * sizeof(ixs_addterm),
                                   sizeof(void *));
  if (!a && nterms > 0)
    return NULL;
  memcpy(a, terms, nterms * sizeof(ixs_addterm));

  ixs_node *n = alloc_node(ctx);
  if (!n)
    return NULL;
  n->tag = IXS_ADD;
  n->u.add.coeff = coeff;
  n->u.add.nterms = nterms;
  n->u.add.terms = a;
  n->hash = compute_hash(n);
  return ixs_htab_intern(ctx, n);
}

ixs_node *ixs_node_mul(ixs_ctx *ctx, ixs_node *coeff, uint32_t nfactors,
                       ixs_mulfactor *factors) {
  ixs_mulfactor *f = ixs_arena_alloc(
      &ctx->arena, nfactors * sizeof(ixs_mulfactor), sizeof(void *));
  if (!f && nfactors > 0)
    return NULL;
  memcpy(f, factors, nfactors * sizeof(ixs_mulfactor));

  ixs_node *n = alloc_node(ctx);
  if (!n)
    return NULL;
  n->tag = IXS_MUL;
  n->u.mul.coeff = coeff;
  n->u.mul.nfactors = nfactors;
  n->u.mul.factors = f;
  n->hash = compute_hash(n);
  return ixs_htab_intern(ctx, n);
}

ixs_node *ixs_node_floor(ixs_ctx *ctx, ixs_node *arg) {
  ixs_node *n = alloc_node(ctx);
  if (!n)
    return NULL;
  n->tag = IXS_FLOOR;
  n->u.unary.arg = arg;
  n->hash = compute_hash(n);
  return ixs_htab_intern(ctx, n);
}

ixs_node *ixs_node_ceil(ixs_ctx *ctx, ixs_node *arg) {
  ixs_node *n = alloc_node(ctx);
  if (!n)
    return NULL;
  n->tag = IXS_CEIL;
  n->u.unary.arg = arg;
  n->hash = compute_hash(n);
  return ixs_htab_intern(ctx, n);
}

ixs_node *ixs_node_binary(ixs_ctx *ctx, ixs_tag tag, ixs_node *lhs,
                          ixs_node *rhs, ixs_cmp_op op) {
  ixs_node *n = alloc_node(ctx);
  if (!n)
    return NULL;
  n->tag = tag;
  n->u.binary.lhs = lhs;
  n->u.binary.rhs = rhs;
  n->u.binary.cmp_op = op;
  n->hash = compute_hash(n);
  return ixs_htab_intern(ctx, n);
}

ixs_node *ixs_node_pw(ixs_ctx *ctx, uint32_t ncases, ixs_pwcase *cases) {
  ixs_pwcase *c =
      ixs_arena_alloc(&ctx->arena, ncases * sizeof(ixs_pwcase), sizeof(void *));
  if (!c && ncases > 0)
    return NULL;
  memcpy(c, cases, ncases * sizeof(ixs_pwcase));

  ixs_node *n = alloc_node(ctx);
  if (!n)
    return NULL;
  n->tag = IXS_PIECEWISE;
  n->u.pw.ncases = ncases;
  n->u.pw.cases = c;
  n->hash = compute_hash(n);
  return ixs_htab_intern(ctx, n);
}

ixs_node *ixs_node_logic(ixs_ctx *ctx, ixs_tag tag, uint32_t nargs,
                         ixs_node **args) {
  ixs_node **a =
      ixs_arena_alloc(&ctx->arena, nargs * sizeof(ixs_node *), sizeof(void *));
  if (!a && nargs > 0)
    return NULL;
  memcpy(a, args, nargs * sizeof(ixs_node *));

  ixs_node *n = alloc_node(ctx);
  if (!n)
    return NULL;
  n->tag = tag;
  n->u.logic.nargs = nargs;
  n->u.logic.args = a;
  n->hash = compute_hash(n);
  return ixs_htab_intern(ctx, n);
}

ixs_node *ixs_node_not(ixs_ctx *ctx, ixs_node *arg) {
  ixs_node *n = alloc_node(ctx);
  if (!n)
    return NULL;
  n->tag = IXS_NOT;
  n->u.unary_bool.arg = arg;
  n->hash = compute_hash(n);
  return ixs_htab_intern(ctx, n);
}

/* ------------------------------------------------------------------ */
/*  Utilities                                                         */
/* ------------------------------------------------------------------ */

bool ixs_node_is_const(const ixs_node *n) {
  return n->tag == IXS_INT || n->tag == IXS_RAT;
}

bool ixs_node_is_int(const ixs_node *n) { return n->tag == IXS_INT; }

bool ixs_node_is_zero(const ixs_node *n) {
  return n->tag == IXS_INT && n->u.ival == 0;
}

bool ixs_node_is_one(const ixs_node *n) {
  return n->tag == IXS_INT && n->u.ival == 1;
}

void ixs_node_get_rat(const ixs_node *n, int64_t *p, int64_t *q) {
  if (n->tag == IXS_INT) {
    *p = n->u.ival;
    *q = 1;
  } else {
    *p = n->u.rat.p;
    *q = n->u.rat.q;
  }
}

bool ixs_node_is_sentinel(const ixs_node *n) {
  return n->tag == IXS_ERROR || n->tag == IXS_PARSE_ERROR;
}

/* ------------------------------------------------------------------ */
/*  Error list                                                        */
/* ------------------------------------------------------------------ */

void ixs_ctx_push_error(ixs_ctx *ctx, const char *fmt, ...) {
  char buf[512];
  va_list ap;
  va_start(ap, fmt);
  vsnprintf(buf, sizeof(buf), fmt, ap);
  va_end(ap);

  char *msg = ixs_arena_strdup(&ctx->arena, buf, strlen(buf));
  if (!msg)
    return;

  if (ctx->nerrors >= ctx->errors_cap) {
    size_t new_cap = ctx->errors_cap ? ctx->errors_cap * 2 : 16;
    const char **new_arr =
        realloc((void *)ctx->errors, new_cap * sizeof(const char *));
    if (!new_arr)
      return;
    ctx->errors = new_arr;
    ctx->errors_cap = new_cap;
  }
  ctx->errors[ctx->nerrors++] = msg;
}

/* ------------------------------------------------------------------ */
/*  NULL / sentinel propagation                                       */
/* ------------------------------------------------------------------ */

ixs_node *ixs_propagate1(ixs_node *a) {
  if (!a)
    return NULL;
  if (ixs_node_is_sentinel(a))
    return a;
  return NULL; /* clean */
}

/*
 * If either arg is a sentinel (ERROR or PARSE_ERROR), return it so
 * the caller can short-circuit.  NULL (OOM) returns NULL — callers
 * propagate that by their own NULL return.  Both clean → NULL.
 */
ixs_node *ixs_propagate2(ixs_node *a, ixs_node *b) {
  if (!a || !b)
    return NULL; /* OOM propagation — caller returns NULL */
  if (a->tag == IXS_PARSE_ERROR || b->tag == IXS_PARSE_ERROR)
    return a->tag == IXS_PARSE_ERROR ? a : b;
  if (a->tag == IXS_ERROR)
    return a;
  if (b->tag == IXS_ERROR)
    return b;
  return NULL; /* both clean */
}

/* ------------------------------------------------------------------ */
/*  Integer-valued predicate                                          */
/* ------------------------------------------------------------------ */

bool ixs_node_is_integer_valued(const ixs_node *n) {
  if (!n)
    return false;
  switch (n->tag) {
  case IXS_INT:
  case IXS_FLOOR:
  case IXS_CEIL:
  case IXS_SYM:
  case IXS_XOR:
    return true;
  case IXS_ADD: {
    uint32_t i;
    int64_t cp, cq;
    ixs_node_get_rat(n->u.add.coeff, &cp, &cq);
    if (cq != 1)
      return false;
    for (i = 0; i < n->u.add.nterms; i++) {
      ixs_node_get_rat(n->u.add.terms[i].coeff, &cp, &cq);
      if (cq != 1)
        return false;
      if (!ixs_node_is_integer_valued(n->u.add.terms[i].term))
        return false;
    }
    return true;
  }
  case IXS_MUL: {
    uint32_t i;
    int64_t cp, cq;
    ixs_node_get_rat(n->u.mul.coeff, &cp, &cq);
    if (cq != 1)
      return false;
    for (i = 0; i < n->u.mul.nfactors; i++) {
      if (n->u.mul.factors[i].exp < 0)
        return false;
      if (!ixs_node_is_integer_valued(n->u.mul.factors[i].base))
        return false;
    }
    return true;
  }
  case IXS_MOD:
  case IXS_MAX:
  case IXS_MIN:
    return ixs_node_is_integer_valued(n->u.binary.lhs) &&
           ixs_node_is_integer_valued(n->u.binary.rhs);
  default:
    return false;
  }
}

/* ==================================================================== */
/* parser.c                                                           */
/* ==================================================================== */

#include "parser.h"
#include "simplify.h"
#include <ctype.h>
#include <limits.h>
#include <string.h>

#define PARSER_MAX_DEPTH 256
#define MAX_TERMS 4096

typedef struct {
  ixs_ctx *ctx;
  const char *input;
  size_t len;
  size_t pos;
  int depth;
  int max_depth;
} parser;

/* --- Lexer helpers --- */

static void skip_ws(parser *p) {
  while (p->pos < p->len &&
         (p->input[p->pos] == ' ' || p->input[p->pos] == '\t' ||
          p->input[p->pos] == '\n' || p->input[p->pos] == '\r'))
    p->pos++;
}

static bool at_end(parser *p) {
  skip_ws(p);
  return p->pos >= p->len;
}

static char peek(parser *p) {
  skip_ws(p);
  if (p->pos >= p->len)
    return '\0';
  return p->input[p->pos];
}

static bool match_char(parser *p, char c) {
  skip_ws(p);
  if (p->pos < p->len && p->input[p->pos] == c) {
    p->pos++;
    return true;
  }
  return false;
}

static bool match_str(parser *p, const char *s) {
  size_t slen = strlen(s);
  skip_ws(p);
  if (p->pos + slen <= p->len && memcmp(p->input + p->pos, s, slen) == 0) {
    /* Check that the next char isn't alphanumeric (keyword boundary). */
    if (slen > 0 && isalpha((unsigned char)s[slen - 1])) {
      if (p->pos + slen < p->len &&
          (isalnum((unsigned char)p->input[p->pos + slen]) ||
           p->input[p->pos + slen] == '_' || p->input[p->pos + slen] == '$'))
        return false;
    }
    p->pos += slen;
    return true;
  }
  return false;
}

static void parse_error(parser *p, const char *msg) {
  ixs_ctx_push_error(p->ctx, "parse error at offset %zu: %s", p->pos, msg);
}

static bool depth_push(parser *p) {
  if (p->depth >= p->max_depth) {
    ixs_ctx_push_error(p->ctx,
                       "parse error: recursion depth limit (%d) exceeded",
                       p->max_depth);
    return false;
  }
  p->depth++;
  return true;
}

static void depth_pop(parser *p) { p->depth--; }

/* --- Forward declarations --- */

static ixs_node *parse_expr(parser *p);
static ixs_node *parse_cond(parser *p);

/* --- Grammar implementation --- */

static ixs_node *parse_int(parser *p) {
  skip_ws(p);
  size_t start = p->pos;
  if (p->pos >= p->len || !isdigit((unsigned char)p->input[p->pos]))
    return NULL;

  int64_t val = 0;
  while (p->pos < p->len && isdigit((unsigned char)p->input[p->pos])) {
    int d = p->input[p->pos] - '0';
    if (val > (INT64_MAX - d) / 10) {
      /* Overflow */
      while (p->pos < p->len && isdigit((unsigned char)p->input[p->pos]))
        p->pos++;
      ixs_ctx_push_error(p->ctx, "integer literal overflow at offset %zu",
                         start);
      return p->ctx->sentinel_error;
    }
    val = val * 10 + d;
    p->pos++;
  }
  return ixs_node_int(p->ctx, val);
}

static ixs_node *parse_symbol(parser *p) {
  skip_ws(p);
  size_t start = p->pos;
  if (p->pos >= p->len)
    return NULL;

  char c = p->input[p->pos];
  if (!isalpha((unsigned char)c) && c != '_' && c != '$')
    return NULL;

  while (p->pos < p->len) {
    c = p->input[p->pos];
    if (isalnum((unsigned char)c) || c == '_' || c == '$')
      p->pos++;
    else
      break;
  }

  return ixs_node_sym(p->ctx, p->input + start, p->pos - start);
}

static ixs_node *parse_atom(parser *p);

static ixs_node *parse_func_1(parser *p, const char *name) {
  (void)name;
  if (!match_char(p, '(')) {
    parse_error(p, "expected '(' after function name");
    return p->ctx->sentinel_parse_error;
  }
  ixs_node *arg = parse_expr(p);
  if (!arg)
    return NULL;
  if (ixs_node_is_sentinel(arg))
    return arg;
  if (!match_char(p, ')')) {
    parse_error(p, "expected ')' after function argument");
    return p->ctx->sentinel_parse_error;
  }
  return arg;
}

static ixs_node *parse_piecewise(parser *p) {
  ixs_node *values[MAX_TERMS], *conds[MAX_TERMS];
  uint32_t n = 0;

  if (!match_char(p, '(')) {
    parse_error(p, "expected '(' after Piecewise");
    return p->ctx->sentinel_parse_error;
  }

  while (!at_end(p) && peek(p) != ')') {
    if (n > 0 && !match_char(p, ',')) {
      parse_error(p, "expected ',' between Piecewise cases");
      return p->ctx->sentinel_parse_error;
    }

    if (!match_char(p, '(')) {
      parse_error(p, "expected '(' for Piecewise case");
      return p->ctx->sentinel_parse_error;
    }

    ixs_node *val = parse_expr(p);
    if (!val)
      return NULL;

    if (!match_char(p, ',')) {
      parse_error(p, "expected ',' in Piecewise case");
      return p->ctx->sentinel_parse_error;
    }

    ixs_node *cond = parse_cond(p);
    if (!cond)
      return NULL;

    if (!match_char(p, ')')) {
      parse_error(p, "expected ')' after Piecewise case");
      return p->ctx->sentinel_parse_error;
    }

    if (n >= MAX_TERMS) {
      parse_error(p, "too many Piecewise cases");
      return p->ctx->sentinel_parse_error;
    }
    values[n] = val;
    conds[n] = cond;
    n++;
  }

  if (!match_char(p, ')')) {
    parse_error(p, "expected ')' after Piecewise");
    return p->ctx->sentinel_parse_error;
  }

  if (n == 0) {
    parse_error(p, "empty Piecewise");
    return p->ctx->sentinel_parse_error;
  }

  return simp_pw(p->ctx, n, values, conds);
}

static ixs_node *parse_atom(parser *p) {
  ixs_node *result;

  if (!depth_push(p))
    return p->ctx->sentinel_parse_error;

  skip_ws(p);

  /* Parenthesized expression */
  if (peek(p) == '(') {
    match_char(p, '(');
    result = parse_expr(p);
    if (!result) {
      depth_pop(p);
      return NULL;
    }
    if (!match_char(p, ')')) {
      parse_error(p, "expected ')'");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    depth_pop(p);
    return result;
  }

  /* Integer literal */
  if (p->pos < p->len && isdigit((unsigned char)p->input[p->pos])) {
    result = parse_int(p);
    depth_pop(p);
    return result;
  }

  /* Keywords / functions */
  if (match_str(p, "floor")) {
    result = parse_func_1(p, "floor");
    depth_pop(p);
    return result ? simp_floor(p->ctx, result) : NULL;
  }
  if (match_str(p, "ceiling")) {
    result = parse_func_1(p, "ceiling");
    depth_pop(p);
    return result ? simp_ceil(p->ctx, result) : NULL;
  }
  if (match_str(p, "Mod")) {
    if (!match_char(p, '(')) {
      parse_error(p, "expected '(' after Mod");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    ixs_node *a = parse_expr(p);
    if (!a) {
      depth_pop(p);
      return NULL;
    }
    if (!match_char(p, ',')) {
      parse_error(p, "expected ',' in Mod");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    ixs_node *b = parse_expr(p);
    if (!b) {
      depth_pop(p);
      return NULL;
    }
    if (!match_char(p, ')')) {
      parse_error(p, "expected ')' after Mod");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    depth_pop(p);
    return simp_mod(p->ctx, a, b);
  }
  if (match_str(p, "Max")) {
    if (!match_char(p, '(')) {
      parse_error(p, "expected '(' after Max");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    ixs_node *a = parse_expr(p);
    if (!a) {
      depth_pop(p);
      return NULL;
    }
    if (!match_char(p, ',')) {
      parse_error(p, "expected ',' in Max");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    ixs_node *b = parse_expr(p);
    if (!b) {
      depth_pop(p);
      return NULL;
    }
    if (!match_char(p, ')')) {
      parse_error(p, "expected ')' after Max");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    depth_pop(p);
    return simp_max(p->ctx, a, b);
  }
  if (match_str(p, "Min")) {
    if (!match_char(p, '(')) {
      parse_error(p, "expected '(' after Min");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    ixs_node *a = parse_expr(p);
    if (!a) {
      depth_pop(p);
      return NULL;
    }
    if (!match_char(p, ',')) {
      parse_error(p, "expected ',' in Min");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    ixs_node *b = parse_expr(p);
    if (!b) {
      depth_pop(p);
      return NULL;
    }
    if (!match_char(p, ')')) {
      parse_error(p, "expected ')' after Min");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    depth_pop(p);
    return simp_min(p->ctx, a, b);
  }
  if (match_str(p, "xor")) {
    if (!match_char(p, '(')) {
      parse_error(p, "expected '(' after xor");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    ixs_node *a = parse_expr(p);
    if (!a) {
      depth_pop(p);
      return NULL;
    }
    if (!match_char(p, ',')) {
      parse_error(p, "expected ',' in xor");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    ixs_node *b = parse_expr(p);
    if (!b) {
      depth_pop(p);
      return NULL;
    }
    if (!match_char(p, ')')) {
      parse_error(p, "expected ')' after xor");
      depth_pop(p);
      return p->ctx->sentinel_parse_error;
    }
    depth_pop(p);
    return simp_xor(p->ctx, a, b);
  }
  if (match_str(p, "Piecewise")) {
    result = parse_piecewise(p);
    depth_pop(p);
    return result;
  }
  if (match_str(p, "True")) {
    depth_pop(p);
    return p->ctx->node_true;
  }
  if (match_str(p, "False")) {
    depth_pop(p);
    return p->ctx->node_false;
  }

  /* Symbol */
  if (p->pos < p->len) {
    char c = p->input[p->pos];
    if (isalpha((unsigned char)c) || c == '_' || c == '$') {
      result = parse_symbol(p);
      depth_pop(p);
      return result;
    }
  }

  parse_error(p, "unexpected token");
  depth_pop(p);
  return p->ctx->sentinel_parse_error;
}

static ixs_node *parse_unary(parser *p) {
  skip_ws(p);
  if (peek(p) == '-') {
    match_char(p, '-');
    ixs_node *a = parse_unary(p);
    if (!a)
      return NULL;
    return simp_neg(p->ctx, a);
  }
  return parse_atom(p);
}

static ixs_node *parse_term(parser *p) {
  ixs_node *left = parse_unary(p);
  if (!left)
    return NULL;

  for (;;) {
    skip_ws(p);
    if (peek(p) == '*') {
      /* Check for ** (power) — not in our grammar, skip. */
      if (p->pos + 1 < p->len && p->input[p->pos + 1] == '*') {
        break; /* Stop, don't consume ** */
      }
      match_char(p, '*');
      ixs_node *right = parse_unary(p);
      if (!right)
        return NULL;
      left = simp_mul(p->ctx, left, right);
      if (!left)
        return NULL;
    } else if (peek(p) == '/') {
      match_char(p, '/');
      ixs_node *right = parse_unary(p);
      if (!right)
        return NULL;
      left = simp_div(p->ctx, left, right);
      if (!left)
        return NULL;
    } else {
      break;
    }
  }
  return left;
}

static ixs_node *parse_expr(parser *p) {
  ixs_node *left = parse_term(p);
  if (!left)
    return NULL;

  for (;;) {
    skip_ws(p);
    if (peek(p) == '+') {
      match_char(p, '+');
      ixs_node *right = parse_term(p);
      if (!right)
        return NULL;
      left = simp_add(p->ctx, left, right);
      if (!left)
        return NULL;
    } else if (peek(p) == '-') {
      match_char(p, '-');
      ixs_node *right = parse_term(p);
      if (!right)
        return NULL;
      left = simp_sub(p->ctx, left, right);
      if (!left)
        return NULL;
    } else {
      break;
    }
  }
  return left;
}

/* --- Condition parsing --- */

static ixs_node *parse_cmp_expr(parser *p);

static ixs_node *parse_cmp_expr(parser *p) {
  skip_ws(p);

  /* ~expr */
  if (peek(p) == '~') {
    match_char(p, '~');
    ixs_node *a = parse_cmp_expr(p);
    if (!a)
      return NULL;
    return simp_not(p->ctx, a);
  }

  /* True / False */
  if (match_str(p, "True"))
    return p->ctx->node_true;
  if (match_str(p, "False"))
    return p->ctx->node_false;

  /* (cond) */
  if (peek(p) == '(') {
    match_char(p, '(');
    ixs_node *c = parse_cond(p);
    if (!c)
      return NULL;
    if (!match_char(p, ')')) {
      parse_error(p, "expected ')' in condition");
      return p->ctx->sentinel_parse_error;
    }
    return c;
  }

  /* expr [cmp_op expr] */
  ixs_node *left = parse_expr(p);
  if (!left)
    return NULL;

  skip_ws(p);
  ixs_cmp_op op;
  bool have_cmp = false;

  if (p->pos + 1 < p->len && p->input[p->pos] == '>' &&
      p->input[p->pos + 1] == '=') {
    p->pos += 2;
    op = IXS_CMP_GE;
    have_cmp = true;
  } else if (p->pos + 1 < p->len && p->input[p->pos] == '<' &&
             p->input[p->pos + 1] == '=') {
    p->pos += 2;
    op = IXS_CMP_LE;
    have_cmp = true;
  } else if (p->pos + 1 < p->len && p->input[p->pos] == '=' &&
             p->input[p->pos + 1] == '=') {
    p->pos += 2;
    op = IXS_CMP_EQ;
    have_cmp = true;
  } else if (p->pos + 1 < p->len && p->input[p->pos] == '!' &&
             p->input[p->pos + 1] == '=') {
    p->pos += 2;
    op = IXS_CMP_NE;
    have_cmp = true;
  } else if (p->pos < p->len && p->input[p->pos] == '>') {
    p->pos++;
    op = IXS_CMP_GT;
    have_cmp = true;
  } else if (p->pos < p->len && p->input[p->pos] == '<') {
    p->pos++;
    op = IXS_CMP_LT;
    have_cmp = true;
  }

  if (have_cmp) {
    ixs_node *right = parse_expr(p);
    if (!right)
      return NULL;
    return simp_cmp(p->ctx, left, op, right);
  }

  /* Bare expression in condition context → e != 0 */
  return simp_cmp(p->ctx, left, IXS_CMP_NE, ixs_node_int(p->ctx, 0));
}

static ixs_node *parse_cond(parser *p) {
  ixs_node *left = parse_cmp_expr(p);
  if (!left)
    return NULL;

  for (;;) {
    skip_ws(p);
    if (peek(p) == '&') {
      match_char(p, '&');
      ixs_node *right = parse_cmp_expr(p);
      if (!right)
        return NULL;
      left = simp_and(p->ctx, left, right);
      if (!left)
        return NULL;
    } else if (peek(p) == '|') {
      match_char(p, '|');
      ixs_node *right = parse_cmp_expr(p);
      if (!right)
        return NULL;
      left = simp_or(p->ctx, left, right);
      if (!left)
        return NULL;
    } else {
      break;
    }
  }
  return left;
}

/* --- Public entry point --- */

ixs_node *ixs_parse_impl(ixs_ctx *ctx, const char *input, size_t len) {
  parser p;
  p.ctx = ctx;
  p.input = input;
  p.len = len;
  p.pos = 0;
  p.depth = 0;
  p.max_depth = PARSER_MAX_DEPTH;

  ixs_node *result = parse_expr(&p);
  if (!result)
    return NULL;

  skip_ws(&p);
  if (p.pos < p.len) {
    parse_error(&p, "trailing characters");
    return ctx->sentinel_parse_error;
  }

  return result;
}

/* ==================================================================== */
/* print.c                                                            */
/* ==================================================================== */

#include "print.h"
#include <stdio.h>
#include <string.h>

/*
 * snprintf-style accumulator: tracks position and remaining space.
 */
typedef struct {
  char *buf;
  size_t size;
  size_t pos; /* total chars written (may exceed size) */
} printbuf;

static void pb_init(printbuf *pb, char *buf, size_t size) {
  pb->buf = buf;
  pb->size = size;
  pb->pos = 0;
}

static void pb_write(printbuf *pb, const char *s, size_t len) {
  if (pb->buf && pb->pos < pb->size) {
    size_t avail = pb->size - pb->pos;
    size_t n = len < avail ? len : avail;
    memcpy(pb->buf + pb->pos, s, n);
  }
  pb->pos += len;
}

static void pb_str(printbuf *pb, const char *s) { pb_write(pb, s, strlen(s)); }

static void pb_char(printbuf *pb, char c) { pb_write(pb, &c, 1); }

static void pb_i64(printbuf *pb, int64_t v) {
  char tmp[32];
  int n = snprintf(tmp, sizeof(tmp), "%lld", (long long)v);
  pb_write(pb, tmp, (size_t)n);
}

static void pb_finish(printbuf *pb) {
  if (pb->buf && pb->size > 0) {
    size_t end = pb->pos < pb->size ? pb->pos : pb->size - 1;
    pb->buf[end] = '\0';
  }
}

/* Precedence levels for minimal parenthesization. */
typedef enum {
  PREC_ATOM = 0,
  PREC_MUL = 1,
  PREC_ADD = 2,
  PREC_CMP = 3,
  PREC_NOT = 4,
  PREC_AND = 5,
  PREC_OR = 6,
  PREC_TOP = 7
} prec_t;

static prec_t node_prec(ixs_node *n) {
  switch (n->tag) {
  case IXS_ADD:
    return PREC_ADD;
  case IXS_MUL:
    return PREC_MUL;
  case IXS_CMP:
    return PREC_CMP;
  case IXS_AND:
    return PREC_AND;
  case IXS_OR:
    return PREC_OR;
  case IXS_NOT:
    return PREC_NOT;
  default:
    return PREC_ATOM;
  }
}

static void print_node(printbuf *pb, ixs_node *n, prec_t parent_prec);

static void print_wrapped(printbuf *pb, ixs_node *n, prec_t parent_prec) {
  prec_t my = node_prec(n);
  if (my > parent_prec) {
    pb_char(pb, '(');
    print_node(pb, n, PREC_TOP);
    pb_char(pb, ')');
  } else {
    print_node(pb, n, parent_prec);
  }
}

static void print_node(printbuf *pb, ixs_node *n, prec_t parent_prec) {
  uint32_t i;
  (void)parent_prec;

  if (!n) {
    pb_str(pb, "<null>");
    return;
  }

  switch (n->tag) {
  case IXS_INT:
    pb_i64(pb, n->u.ival);
    break;

  case IXS_RAT:
    pb_i64(pb, n->u.rat.p);
    pb_char(pb, '/');
    pb_i64(pb, n->u.rat.q);
    break;

  case IXS_SYM:
    pb_str(pb, n->u.name);
    break;

  case IXS_ADD: {
    int64_t cp, cq;
    bool first = true;

    /* Print constant term first if nonzero. */
    ixs_node_get_rat(n->u.add.coeff, &cp, &cq);
    if (!ixs_rat_is_zero(cp)) {
      print_node(pb, n->u.add.coeff, PREC_ADD);
      first = false;
    }

    for (i = 0; i < n->u.add.nterms; i++) {
      int64_t tp, tq;
      ixs_node_get_rat(n->u.add.terms[i].coeff, &tp, &tq);

      if (first) {
        if (tp == -1 && tq == 1) {
          pb_str(pb, "-");
          print_wrapped(pb, n->u.add.terms[i].term, PREC_MUL);
        } else if (tp == 1 && tq == 1) {
          print_wrapped(pb, n->u.add.terms[i].term, PREC_ADD);
        } else if (ixs_rat_is_neg(tp)) {
          pb_str(pb, "-");
          int64_t np = 0, nq = 0;
          ixs_rat_neg(tp, tq, &np, &nq);
          if (np == 1 && nq == 1) {
            print_wrapped(pb, n->u.add.terms[i].term, PREC_MUL);
          } else {
            ixs_node tmp;
            memset(&tmp, 0, sizeof(tmp));
            if (nq == 1) {
              tmp.tag = IXS_INT;
              tmp.u.ival = np;
            } else {
              tmp.tag = IXS_RAT;
              tmp.u.rat.p = np;
              tmp.u.rat.q = nq;
            }
            print_node(pb, &tmp, PREC_MUL);
            pb_char(pb, '*');
            print_wrapped(pb, n->u.add.terms[i].term, PREC_MUL);
          }
        } else {
          if (!(tp == 1 && tq == 1)) {
            print_node(pb, n->u.add.terms[i].coeff, PREC_MUL);
            pb_char(pb, '*');
          }
          print_wrapped(pb, n->u.add.terms[i].term, PREC_ADD);
        }
        first = false;
      } else {
        if (ixs_rat_is_neg(tp)) {
          pb_str(pb, " - ");
          int64_t np = 0, nq = 0;
          ixs_rat_neg(tp, tq, &np, &nq);
          if (np == 1 && nq == 1) {
            print_wrapped(pb, n->u.add.terms[i].term, PREC_MUL);
          } else {
            ixs_node tmp;
            memset(&tmp, 0, sizeof(tmp));
            if (nq == 1) {
              tmp.tag = IXS_INT;
              tmp.u.ival = np;
            } else {
              tmp.tag = IXS_RAT;
              tmp.u.rat.p = np;
              tmp.u.rat.q = nq;
            }
            print_node(pb, &tmp, PREC_MUL);
            pb_char(pb, '*');
            print_wrapped(pb, n->u.add.terms[i].term, PREC_MUL);
          }
        } else {
          pb_str(pb, " + ");
          if (!(tp == 1 && tq == 1)) {
            print_node(pb, n->u.add.terms[i].coeff, PREC_MUL);
            pb_char(pb, '*');
          }
          print_wrapped(pb, n->u.add.terms[i].term, PREC_MUL);
        }
      }
    }
    if (first)
      pb_str(pb, "0");
    break;
  }

  case IXS_MUL: {
    int64_t cp, cq;
    ixs_node_get_rat(n->u.mul.coeff, &cp, &cq);
    bool need_sep = false;

    if (cp == -1 && cq == 1) {
      pb_str(pb, "-");
    } else if (!(cp == 1 && cq == 1)) {
      print_node(pb, n->u.mul.coeff, PREC_MUL);
      need_sep = true;
    }

    for (i = 0; i < n->u.mul.nfactors; i++) {
      if (need_sep)
        pb_char(pb, '*');
      if (n->u.mul.factors[i].exp == 1) {
        print_wrapped(pb, n->u.mul.factors[i].base, PREC_MUL);
      } else if (n->u.mul.factors[i].exp == -1) {
        pb_str(pb, "1/");
        print_wrapped(pb, n->u.mul.factors[i].base, PREC_MUL);
      } else {
        print_wrapped(pb, n->u.mul.factors[i].base, PREC_ATOM);
        pb_str(pb, "**");
        pb_i64(pb, n->u.mul.factors[i].exp);
      }
      need_sep = true;
    }
    break;
  }

  case IXS_FLOOR:
    pb_str(pb, "floor(");
    print_node(pb, n->u.unary.arg, PREC_TOP);
    pb_char(pb, ')');
    break;

  case IXS_CEIL:
    pb_str(pb, "ceiling(");
    print_node(pb, n->u.unary.arg, PREC_TOP);
    pb_char(pb, ')');
    break;

  case IXS_MOD:
    pb_str(pb, "Mod(");
    print_node(pb, n->u.binary.lhs, PREC_TOP);
    pb_str(pb, ", ");
    print_node(pb, n->u.binary.rhs, PREC_TOP);
    pb_char(pb, ')');
    break;

  case IXS_MAX:
    pb_str(pb, "Max(");
    print_node(pb, n->u.binary.lhs, PREC_TOP);
    pb_str(pb, ", ");
    print_node(pb, n->u.binary.rhs, PREC_TOP);
    pb_char(pb, ')');
    break;

  case IXS_MIN:
    pb_str(pb, "Min(");
    print_node(pb, n->u.binary.lhs, PREC_TOP);
    pb_str(pb, ", ");
    print_node(pb, n->u.binary.rhs, PREC_TOP);
    pb_char(pb, ')');
    break;

  case IXS_XOR:
    pb_str(pb, "xor(");
    print_node(pb, n->u.binary.lhs, PREC_TOP);
    pb_str(pb, ", ");
    print_node(pb, n->u.binary.rhs, PREC_TOP);
    pb_char(pb, ')');
    break;

  case IXS_CMP: {
    const char *opstr = "??";
    switch (n->u.binary.cmp_op) {
    case IXS_CMP_GT:
      opstr = " > ";
      break;
    case IXS_CMP_GE:
      opstr = " >= ";
      break;
    case IXS_CMP_LT:
      opstr = " < ";
      break;
    case IXS_CMP_LE:
      opstr = " <= ";
      break;
    case IXS_CMP_EQ:
      opstr = " == ";
      break;
    case IXS_CMP_NE:
      opstr = " != ";
      break;
    }
    print_wrapped(pb, n->u.binary.lhs, PREC_CMP);
    pb_str(pb, opstr);
    print_wrapped(pb, n->u.binary.rhs, PREC_CMP);
    break;
  }

  case IXS_PIECEWISE:
    pb_str(pb, "Piecewise(");
    for (i = 0; i < n->u.pw.ncases; i++) {
      if (i > 0)
        pb_str(pb, ", ");
      pb_char(pb, '(');
      print_node(pb, n->u.pw.cases[i].value, PREC_TOP);
      pb_str(pb, ", ");
      print_node(pb, n->u.pw.cases[i].cond, PREC_TOP);
      pb_char(pb, ')');
    }
    pb_char(pb, ')');
    break;

  case IXS_AND:
    for (i = 0; i < n->u.logic.nargs; i++) {
      if (i > 0)
        pb_str(pb, " & ");
      print_wrapped(pb, n->u.logic.args[i], PREC_AND);
    }
    break;

  case IXS_OR:
    for (i = 0; i < n->u.logic.nargs; i++) {
      if (i > 0)
        pb_str(pb, " | ");
      print_wrapped(pb, n->u.logic.args[i], PREC_OR);
    }
    break;

  case IXS_NOT:
    pb_str(pb, "~");
    print_wrapped(pb, n->u.unary_bool.arg, PREC_NOT);
    break;

  case IXS_TRUE:
    pb_str(pb, "True");
    break;

  case IXS_FALSE:
    pb_str(pb, "False");
    break;

  case IXS_ERROR:
  case IXS_PARSE_ERROR:
    pb_str(pb, "<error>");
    break;
  }
}

size_t ixs_print_impl(ixs_node *expr, char *buf, size_t bufsize) {
  printbuf pb;
  if (!expr) {
    if (buf && bufsize > 0)
      buf[0] = '\0';
    return 0;
  }
  pb_init(&pb, buf, bufsize);
  print_node(&pb, expr, PREC_TOP);
  pb_finish(&pb);
  return pb.pos;
}

/* ------------------------------------------------------------------ */
/*  C output mode                                                     */
/* ------------------------------------------------------------------ */

static void print_c_node(printbuf *pb, ixs_node *n, prec_t parent_prec);

static void print_c_wrapped(printbuf *pb, ixs_node *n, prec_t parent_prec) {
  prec_t my = node_prec(n);
  if (my > parent_prec) {
    pb_char(pb, '(');
    print_c_node(pb, n, PREC_TOP);
    pb_char(pb, ')');
  } else {
    print_c_node(pb, n, parent_prec);
  }
}

static void print_c_node(printbuf *pb, ixs_node *n, prec_t parent_prec) {
  (void)parent_prec;

  if (!n) {
    pb_str(pb, "/*null*/0");
    return;
  }

  switch (n->tag) {
  case IXS_INT:
    pb_i64(pb, n->u.ival);
    break;
  case IXS_RAT: {
    char tmp[64];
    int len = snprintf(tmp, sizeof(tmp), "(%lld.0/%lld.0)",
                       (long long)n->u.rat.p, (long long)n->u.rat.q);
    pb_write(pb, tmp, (size_t)len);
    break;
  }
  case IXS_SYM:
    pb_str(pb, n->u.name);
    break;
  case IXS_FLOOR:
    pb_str(pb, "ixs_floor_i(");
    print_c_node(pb, n->u.unary.arg, PREC_TOP);
    pb_char(pb, ')');
    break;
  case IXS_CEIL:
    pb_str(pb, "ixs_ceil_i(");
    print_c_node(pb, n->u.unary.arg, PREC_TOP);
    pb_char(pb, ')');
    break;
  case IXS_MOD:
    pb_str(pb, "ixs_mod_i(");
    print_c_node(pb, n->u.binary.lhs, PREC_TOP);
    pb_str(pb, ", ");
    print_c_node(pb, n->u.binary.rhs, PREC_TOP);
    pb_char(pb, ')');
    break;
  case IXS_MAX:
    pb_str(pb, "ixs_max_i(");
    print_c_node(pb, n->u.binary.lhs, PREC_TOP);
    pb_str(pb, ", ");
    print_c_node(pb, n->u.binary.rhs, PREC_TOP);
    pb_char(pb, ')');
    break;
  case IXS_MIN:
    pb_str(pb, "ixs_min_i(");
    print_c_node(pb, n->u.binary.lhs, PREC_TOP);
    pb_str(pb, ", ");
    print_c_node(pb, n->u.binary.rhs, PREC_TOP);
    pb_char(pb, ')');
    break;
  case IXS_XOR:
    pb_char(pb, '(');
    print_c_wrapped(pb, n->u.binary.lhs, PREC_ATOM);
    pb_str(pb, " ^ ");
    print_c_wrapped(pb, n->u.binary.rhs, PREC_ATOM);
    pb_char(pb, ')');
    break;
  default:
    /* Fall back to SymPy format for complex nodes. */
    print_node(pb, n, parent_prec);
    break;
  }
}

size_t ixs_print_c_impl(ixs_node *expr, char *buf, size_t bufsize) {
  printbuf pb;
  if (!expr) {
    if (buf && bufsize > 0)
      buf[0] = '\0';
    return 0;
  }
  pb_init(&pb, buf, bufsize);
  print_c_node(&pb, expr, PREC_TOP);
  pb_finish(&pb);
  return pb.pos;
}

/* ==================================================================== */
/* rational.c                                                         */
/* ==================================================================== */

#include "rational.h"
#include <limits.h>

#ifndef INT64_MIN
#define INT64_MIN (-9223372036854775807LL - 1)
#endif
#ifndef INT64_MAX
#define INT64_MAX 9223372036854775807LL
#endif

/* --- Safe arithmetic --- */

bool ixs_safe_add(int64_t a, int64_t b, int64_t *r) {
  if (b > 0 && a > INT64_MAX - b)
    return false;
  if (b < 0 && a < INT64_MIN - b)
    return false;
  *r = a + b;
  return true;
}

bool ixs_safe_sub(int64_t a, int64_t b, int64_t *r) {
  if (b < 0 && a > INT64_MAX + b)
    return false;
  if (b > 0 && a < INT64_MIN + b)
    return false;
  *r = a - b;
  return true;
}

bool ixs_safe_mul(int64_t a, int64_t b, int64_t *r) {
  if (a == 0 || b == 0) {
    *r = 0;
    return true;
  }
  if (a == 1) {
    *r = b;
    return true;
  }
  if (b == 1) {
    *r = a;
    return true;
  }
  if (a == -1)
    return ixs_safe_neg(b, r);
  if (b == -1)
    return ixs_safe_neg(a, r);

  /* Both non-zero, neither +-1. Check overflow. */
  if (a > 0) {
    if (b > 0) {
      if (a > INT64_MAX / b)
        return false;
    } else {
      if (b < INT64_MIN / a)
        return false;
    }
  } else {
    if (b > 0) {
      if (a < INT64_MIN / b)
        return false;
    } else {
      if (a < INT64_MAX / b)
        return false; /* (-a)*(-b) overflow */
    }
  }
  *r = a * b;
  return true;
}

bool ixs_safe_neg(int64_t a, int64_t *r) {
  if (a == INT64_MIN)
    return false;
  *r = -a;
  return true;
}

/* --- GCD --- */

/*
 * Binary GCD. Handles INT64_MIN by treating magnitudes as unsigned.
 * gcd(0, 0) = 0. Result is always >= 0.
 */
static uint64_t to_unsigned_mag(int64_t x) {
  if (x >= 0)
    return (uint64_t)x;
  /* x == INT64_MIN: magnitude is 2^63 = (uint64_t)INT64_MAX + 1 */
  return (uint64_t)(-(x + 1)) + 1u;
}

static int64_t u64_to_i64_clamped(uint64_t u) {
  return (u > (uint64_t)INT64_MAX) ? INT64_MAX : (int64_t)u;
}

int64_t ixs_gcd(int64_t a, int64_t b) {
  uint64_t u = to_unsigned_mag(a);
  uint64_t v = to_unsigned_mag(b);
  unsigned shift;

  if (u == 0)
    return u64_to_i64_clamped(v);
  if (v == 0)
    return u64_to_i64_clamped(u);

  /* Factor out common 2s */
  for (shift = 0; ((u | v) & 1) == 0; ++shift) {
    u >>= 1;
    v >>= 1;
  }
  while ((u & 1) == 0)
    u >>= 1;

  do {
    while ((v & 1) == 0)
      v >>= 1;
    if (u > v) {
      uint64_t t = u;
      u = v;
      v = t;
    }
    v -= u;
  } while (v != 0);

  u <<= shift;
  return u64_to_i64_clamped(u);
}

/* --- Normalize --- */

bool ixs_rat_normalize(int64_t p, int64_t q, int64_t *rp, int64_t *rq) {
  if (q == 0)
    return false;

  if (p == 0) {
    *rp = 0;
    *rq = 1;
    return true;
  }

  /* Make q positive */
  if (q < 0) {
    if (q == INT64_MIN || p == INT64_MIN)
      return false;
    p = -p;
    q = -q;
  }

  int64_t g = ixs_gcd(p, q);
  if (g > 1) {
    p /= g;
    q /= g;
  }

  *rp = p;
  *rq = q;
  return true;
}

/* --- Arithmetic --- */

bool ixs_rat_add(int64_t ap, int64_t aq, int64_t bp, int64_t bq, int64_t *rp,
                 int64_t *rq) {
  /*
   * a/aq + b/bq = (a*bq + b*aq) / (aq*bq)
   * Reduce first to limit overflow: divide by gcd(aq, bq).
   */
  int64_t g = ixs_gcd(aq, bq);
  int64_t aq_r = aq / g;
  int64_t bq_r = bq / g;

  int64_t t1, t2, num, den;
  if (!ixs_safe_mul(ap, bq_r, &t1))
    return false;
  if (!ixs_safe_mul(bp, aq_r, &t2))
    return false;
  if (!ixs_safe_add(t1, t2, &num))
    return false;
  if (!ixs_safe_mul(aq_r, bq, &den))
    return false;

  return ixs_rat_normalize(num, den, rp, rq);
}

bool ixs_rat_sub(int64_t ap, int64_t aq, int64_t bp, int64_t bq, int64_t *rp,
                 int64_t *rq) {
  int64_t neg_bp;
  if (!ixs_safe_neg(bp, &neg_bp))
    return false;
  return ixs_rat_add(ap, aq, neg_bp, bq, rp, rq);
}

bool ixs_rat_mul(int64_t ap, int64_t aq, int64_t bp, int64_t bq, int64_t *rp,
                 int64_t *rq) {
  /* Cross-reduce to limit overflow: gcd(ap, bq) and gcd(bp, aq) */
  int64_t g1 = ixs_gcd(ap, bq);
  int64_t g2 = ixs_gcd(bp, aq);
  int64_t a2 = ap / g1;
  int64_t b2 = bq / g1;
  int64_t c2 = bp / g2;
  int64_t d2 = aq / g2;

  int64_t num, den;
  if (!ixs_safe_mul(a2, c2, &num))
    return false;
  if (!ixs_safe_mul(d2, b2, &den))
    return false;

  return ixs_rat_normalize(num, den, rp, rq);
}

bool ixs_rat_div(int64_t ap, int64_t aq, int64_t bp, int64_t bq, int64_t *rp,
                 int64_t *rq) {
  if (bp == 0)
    return false;
  return ixs_rat_mul(ap, aq, bq, bp, rp, rq);
}

bool ixs_rat_neg(int64_t p, int64_t q, int64_t *rp, int64_t *rq) {
  if (!ixs_safe_neg(p, rp))
    return false;
  *rq = q;
  return true;
}

/* --- Floor / Ceil --- */

/*
 * Floored division: floor(p / q) for q > 0.
 * C division truncates toward zero; we adjust for negative dividends.
 */
int64_t ixs_rat_floor(int64_t p, int64_t q) {
  int64_t d = p / q;
  int64_t r = p % q;
  /* If remainder is negative, floor is one less than truncated. */
  if (r < 0)
    d -= 1;
  return d;
}

int64_t ixs_rat_ceil(int64_t p, int64_t q) {
  int64_t d = p / q;
  int64_t r = p % q;
  /* If remainder is positive, ceil is one more than truncated. */
  if (r > 0)
    d += 1;
  return d;
}

/* --- Floored mod --- */

bool ixs_rat_mod(int64_t ap, int64_t aq, int64_t bp, int64_t bq, int64_t *rp,
                 int64_t *rq) {
  /* mod(a, b) = a - b * floor(a / b) */
  int64_t dp, dq;
  if (!ixs_rat_div(ap, aq, bp, bq, &dp, &dq))
    return false;

  /* f = floor(dp/dq) */
  int64_t f = ixs_rat_floor(dp, dq);

  /* b * f */
  int64_t tp, tq;
  if (!ixs_rat_mul(bp, bq, f, 1, &tp, &tq))
    return false;

  /* a - b*f */
  return ixs_rat_sub(ap, aq, tp, tq, rp, rq);
}

/* --- Compare --- */

int ixs_rat_cmp(int64_t ap, int64_t aq, int64_t bp, int64_t bq) {
  /*
   * Compare a/aq vs b/bq where aq, bq > 0.
   * Equivalent to sign(a*bq - b*aq).
   * Use 128-bit to avoid overflow. Pure C99: emulate with two 64-bit ops.
   */
  /* For the domain of this library, values are small enough that
   * cross-multiply won't overflow. If it does, fall back to comparing
   * differences of reduced fractions. */
  int64_t lhs, rhs;
  bool ok1 = ixs_safe_mul(ap, bq, &lhs);
  bool ok2 = ixs_safe_mul(bp, aq, &rhs);

  if (ok1 && ok2) {
    if (lhs < rhs)
      return -1;
    if (lhs > rhs)
      return 1;
    return 0;
  }

  /* Fallback: reduce and compare. In practice this domain doesn't need it. */
  int64_t dp, dq;
  if (ixs_rat_sub(ap, aq, bp, bq, &dp, &dq)) {
    if (dp == 0)
      return 0;
    return (dp > 0) == (dq > 0) ? 1 : -1;
  }

  /* Absolute last resort: compare doubles. */
  {
    double da = (double)ap / (double)aq;
    double db = (double)bp / (double)bq;
    if (da < db)
      return -1;
    if (da > db)
      return 1;
    return 0;
  }
}

/* ==================================================================== */
/* simplify.c                                                         */
/* ==================================================================== */

#include "simplify.h"
#include "bounds.h"
#include <stdlib.h>
#include <string.h>

/* Max terms/factors in a single flattened add/mul before we bail. */
#define MAX_TERMS 4096
#define SIMPLIFY_ITER_LIMIT 64

/* ------------------------------------------------------------------ */
/*  Helpers                                                           */
/* ------------------------------------------------------------------ */

static ixs_node *make_const(ixs_ctx *ctx, int64_t p, int64_t q) {
  if (q == 1)
    return ixs_node_int(ctx, p);
  return ixs_node_rat(ctx, p, q);
}

/*
 * Extract the additive coefficient and base from a node.
 * For MUL(coeff, factors): coefficient = coeff, base = MUL(1, factors)
 * For INT/RAT: pure constant.
 * For anything else: coefficient = 1, base = node.
 */
static void add_decompose(ixs_ctx *ctx, ixs_node *n, int64_t *cp, int64_t *cq,
                          ixs_node **base) {
  if (!n) {
    *cp = 0;
    *cq = 1;
    *base = NULL;
    return;
  }

  if (n->tag == IXS_INT) {
    *cp = n->u.ival;
    *cq = 1;
    *base = NULL;
    return;
  }
  if (n->tag == IXS_RAT) {
    *cp = n->u.rat.p;
    *cq = n->u.rat.q;
    *base = NULL;
    return;
  }
  if (n->tag == IXS_MUL && ixs_node_is_const(n->u.mul.coeff)) {
    ixs_node_get_rat(n->u.mul.coeff, cp, cq);
    if (n->u.mul.nfactors == 1 && n->u.mul.factors[0].exp == 1) {
      *base = n->u.mul.factors[0].base;
    } else {
      /* Rebuild MUL with coeff=1 */
      *base = ixs_node_mul(ctx, ixs_node_int(ctx, 1), n->u.mul.nfactors,
                           n->u.mul.factors);
    }
    return;
  }
  *cp = 1;
  *cq = 1;
  *base = n;
}

/* Sorting comparator for addterms by their base node. */
static int addterm_cmp(const void *a, const void *b) {
  const ixs_addterm *ta = (const ixs_addterm *)a;
  const ixs_addterm *tb = (const ixs_addterm *)b;
  return ixs_node_cmp(ta->term, tb->term);
}

/* Sorting comparator for mulfactors by their base node. */
static int mulfactor_cmp(const void *a, const void *b) {
  const ixs_mulfactor *fa = (const ixs_mulfactor *)a;
  const ixs_mulfactor *fb = (const ixs_mulfactor *)b;
  return ixs_node_cmp(fa->base, fb->base);
}

/* Sorting comparator for logic args. */
static int nodeptr_cmp(const void *a, const void *b) {
  const ixs_node *na = *(const ixs_node *const *)a;
  const ixs_node *nb = *(const ixs_node *const *)b;
  return ixs_node_cmp(na, nb);
}

/* ------------------------------------------------------------------ */
/*  simp_add                                                          */
/* ------------------------------------------------------------------ */

ixs_node *simp_add(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  ixs_node *prop;
  int64_t const_p = 0, const_q = 1;
  ixs_addterm terms[MAX_TERMS];
  uint32_t nterms = 0;
  uint32_t i, j;

  if (!a || !b)
    return NULL;
  prop = ixs_propagate2(a, b);
  if (prop)
    return prop;

  /* Gather all additive components from a and b. */
  ixs_node *inputs[2];
  inputs[0] = a;
  inputs[1] = b;

  for (i = 0; i < 2; i++) {
    ixs_node *x = inputs[i];
    if (x->tag == IXS_ADD) {
      /* Flatten: add the constant and all terms. */
      int64_t cp, cq;
      ixs_node_get_rat(x->u.add.coeff, &cp, &cq);
      if (!ixs_rat_add(const_p, const_q, cp, cq, &const_p, &const_q))
        goto overflow;
      for (j = 0; j < x->u.add.nterms && nterms < MAX_TERMS; j++)
        terms[nterms++] = x->u.add.terms[j];
    } else {
      int64_t cp, cq;
      ixs_node *base;
      add_decompose(ctx, x, &cp, &cq, &base);
      if (!base) {
        /* Pure constant */
        if (!ixs_rat_add(const_p, const_q, cp, cq, &const_p, &const_q))
          goto overflow;
      } else {
        if (nterms >= MAX_TERMS)
          goto overflow;
        terms[nterms].term = base;
        terms[nterms].coeff = make_const(ctx, cp, cq);
        if (!terms[nterms].coeff)
          return NULL;
        nterms++;
      }
    }
  }

  /* Sort terms by base. */
  if (nterms > 1)
    qsort(terms, nterms, sizeof(ixs_addterm), addterm_cmp);

  /* Collect like terms. */
  j = 0;
  for (i = 0; i < nterms; i++) {
    if (j > 0 && terms[j - 1].term == terms[i].term) {
      int64_t ap2, aq2, bp2, bq2, rp, rq;
      ixs_node_get_rat(terms[j - 1].coeff, &ap2, &aq2);
      ixs_node_get_rat(terms[i].coeff, &bp2, &bq2);
      if (!ixs_rat_add(ap2, aq2, bp2, bq2, &rp, &rq))
        goto overflow;
      if (ixs_rat_is_zero(rp)) {
        j--; /* Drop zero-coefficient term */
      } else {
        terms[j - 1].coeff = make_const(ctx, rp, rq);
        if (!terms[j - 1].coeff)
          return NULL;
      }
    } else {
      if (j != i)
        terms[j] = terms[i];
      j++;
    }
  }
  nterms = j;

  /* Result cases. */
  if (nterms == 0)
    return make_const(ctx, const_p, const_q);

  if (nterms == 1 && ixs_rat_is_zero(const_p)) {
    int64_t cp, cq;
    ixs_node_get_rat(terms[0].coeff, &cp, &cq);
    if (ixs_rat_is_one(cp, cq))
      return terms[0].term;
    /* c * term → MUL(c, term) */
    return simp_mul(ctx, make_const(ctx, cp, cq), terms[0].term);
  }

  {
    ixs_node *coeff = make_const(ctx, const_p, const_q);
    if (!coeff)
      return NULL;
    return ixs_node_add(ctx, coeff, nterms, terms);
  }

overflow:
  ixs_ctx_push_error(ctx, "rational overflow in add");
  return ctx->sentinel_error;
}

/* ------------------------------------------------------------------ */
/*  simp_mul                                                          */
/* ------------------------------------------------------------------ */

ixs_node *simp_mul(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  ixs_node *prop;
  int64_t coeff_p = 1, coeff_q = 1;
  ixs_mulfactor factors[MAX_TERMS];
  uint32_t nfactors = 0;
  uint32_t i, j;

  if (!a || !b)
    return NULL;
  prop = ixs_propagate2(a, b);
  if (prop)
    return prop;

  /* Gather multiplicative components. */
  ixs_node *inputs[2];
  inputs[0] = a;
  inputs[1] = b;

  for (i = 0; i < 2; i++) {
    ixs_node *x = inputs[i];
    if (ixs_node_is_const(x)) {
      int64_t xp, xq;
      ixs_node_get_rat(x, &xp, &xq);
      if (!ixs_rat_mul(coeff_p, coeff_q, xp, xq, &coeff_p, &coeff_q))
        goto overflow;
    } else if (x->tag == IXS_MUL) {
      int64_t cp, cq;
      ixs_node_get_rat(x->u.mul.coeff, &cp, &cq);
      if (!ixs_rat_mul(coeff_p, coeff_q, cp, cq, &coeff_p, &coeff_q))
        goto overflow;
      for (j = 0; j < x->u.mul.nfactors && nfactors < MAX_TERMS; j++)
        factors[nfactors++] = x->u.mul.factors[j];
    } else {
      if (nfactors >= MAX_TERMS)
        goto overflow;
      factors[nfactors].base = x;
      factors[nfactors].exp = 1;
      nfactors++;
    }
  }

  /* Short-circuit: coeff is zero → result is zero. */
  if (ixs_rat_is_zero(coeff_p))
    return ixs_node_int(ctx, 0);

  /* Sort factors by base. */
  if (nfactors > 1)
    qsort(factors, nfactors, sizeof(ixs_mulfactor), mulfactor_cmp);

  /* Collect like bases. */
  j = 0;
  for (i = 0; i < nfactors; i++) {
    if (j > 0 && factors[j - 1].base == factors[i].base) {
      int64_t new_exp = (int64_t)factors[j - 1].exp + (int64_t)factors[i].exp;
      if (new_exp > INT32_MAX || new_exp < INT32_MIN)
        goto overflow;
      if (new_exp == 0) {
        j--; /* base^0 = 1, drop */
      } else {
        factors[j - 1].exp = (int32_t)new_exp;
      }
    } else {
      if (j != i)
        factors[j] = factors[i];
      j++;
    }
  }
  nfactors = j;

  /* Result cases. */
  if (nfactors == 0)
    return make_const(ctx, coeff_p, coeff_q);

  if (nfactors == 1 && factors[0].exp == 1 && ixs_rat_is_one(coeff_p, coeff_q))
    return factors[0].base;

  {
    ixs_node *coeff = make_const(ctx, coeff_p, coeff_q);
    if (!coeff)
      return NULL;
    return ixs_node_mul(ctx, coeff, nfactors, factors);
  }

overflow:
  ixs_ctx_push_error(ctx, "rational overflow in multiply");
  return ctx->sentinel_error;
}

/* ------------------------------------------------------------------ */
/*  simp_neg / simp_sub / simp_div                                    */
/* ------------------------------------------------------------------ */

ixs_node *simp_neg(ixs_ctx *ctx, ixs_node *a) {
  ixs_node *prop = ixs_propagate1(a);
  if (prop)
    return prop;
  return simp_mul(ctx, ixs_node_int(ctx, -1), a);
}

ixs_node *simp_sub(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  if (!a || !b)
    return NULL;
  ixs_node *prop = ixs_propagate2(a, b);
  if (prop)
    return prop;
  return simp_add(ctx, a, simp_neg(ctx, b));
}

ixs_node *simp_div(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  if (!a || !b)
    return NULL;
  ixs_node *prop = ixs_propagate2(a, b);
  if (prop)
    return prop;

  /* Division by zero */
  if (ixs_node_is_zero(b)) {
    ixs_ctx_push_error(ctx, "division by zero");
    return ctx->sentinel_error;
  }

  /* Constant / constant → rational fold */
  if (ixs_node_is_const(a) && ixs_node_is_const(b)) {
    int64_t ap, aq, bp, bq, rp, rq;
    ixs_node_get_rat(a, &ap, &aq);
    ixs_node_get_rat(b, &bp, &bq);
    if (!ixs_rat_div(ap, aq, bp, bq, &rp, &rq)) {
      ixs_ctx_push_error(ctx, "rational overflow in division");
      return ctx->sentinel_error;
    }
    return make_const(ctx, rp, rq);
  }

  /* expr / constant → multiply by reciprocal */
  if (ixs_node_is_const(b)) {
    int64_t bp, bq, rp, rq;
    ixs_node_get_rat(b, &bp, &bq);
    if (!ixs_rat_div(1, 1, bp, bq, &rp, &rq)) {
      ixs_ctx_push_error(ctx, "rational overflow in division");
      return ctx->sentinel_error;
    }
    return simp_mul(ctx, make_const(ctx, rp, rq), a);
  }

  /* General: a * b^(-1) */
  {
    ixs_mulfactor f;
    f.base = b;
    f.exp = -1;
    ixs_node *binv = ixs_node_mul(ctx, ixs_node_int(ctx, 1), 1, &f);
    if (!binv)
      return NULL;
    return simp_mul(ctx, a, binv);
  }
}

/* ------------------------------------------------------------------ */
/*  simp_floor / simp_ceil                                            */
/* ------------------------------------------------------------------ */

ixs_node *simp_floor(ixs_ctx *ctx, ixs_node *x) {
  ixs_node *prop = ixs_propagate1(x);
  if (prop)
    return prop;

  /* floor(integer) → identity */
  if (x->tag == IXS_INT)
    return x;

  /* floor(p/q) → constant fold */
  if (x->tag == IXS_RAT)
    return ixs_node_int(ctx, ixs_rat_floor(x->u.rat.p, x->u.rat.q));

  /* floor(floor(x)) → floor(x), floor(ceil(x)) → ceil(x) */
  if (x->tag == IXS_FLOOR || x->tag == IXS_CEIL)
    return x;

  /* floor(x) → x when x is structurally integer-valued */
  if (ixs_node_is_integer_valued(x))
    return x;

  /* floor(x + n) where n is integer → floor(x) + n
   * Applies when x is ADD and has an integer constant part. */
  if (x->tag == IXS_ADD && x->u.add.coeff->tag == IXS_INT &&
      x->u.add.coeff->u.ival != 0) {
    int64_t n = x->u.add.coeff->u.ival;
    /* Build the ADD without the integer constant. */
    ixs_node *zero = ixs_node_int(ctx, 0);
    if (!zero)
      return NULL;
    ixs_node *inner;
    if (x->u.add.nterms == 1) {
      int64_t cp, cq;
      ixs_node_get_rat(x->u.add.terms[0].coeff, &cp, &cq);
      if (ixs_rat_is_one(cp, cq))
        inner = x->u.add.terms[0].term;
      else
        inner = ixs_node_add(ctx, zero, x->u.add.nterms, x->u.add.terms);
    } else {
      inner = ixs_node_add(ctx, zero, x->u.add.nterms, x->u.add.terms);
    }
    if (!inner)
      return NULL;
    return simp_add(ctx, simp_floor(ctx, inner), ixs_node_int(ctx, n));
  }

  /* floor(floor(y)/b) → floor(y/b) for positive integer b. */
  if (x->tag == IXS_MUL && x->u.mul.nfactors == 1 &&
      x->u.mul.factors[0].exp == 1 &&
      x->u.mul.factors[0].base->tag == IXS_FLOOR) {
    int64_t cp, cq;
    ixs_node_get_rat(x->u.mul.coeff, &cp, &cq);
    if (cp == 1 && cq > 1) {
      ixs_node *inner_arg = x->u.mul.factors[0].base->u.unary.arg;
      ixs_node *scaled = simp_mul(ctx, x->u.mul.coeff, inner_arg);
      if (!scaled)
        return NULL;
      return simp_floor(ctx, scaled);
    }
  }

  return ixs_node_floor(ctx, x);
}

ixs_node *simp_ceil(ixs_ctx *ctx, ixs_node *x) {
  ixs_node *prop = ixs_propagate1(x);
  if (prop)
    return prop;

  if (x->tag == IXS_INT)
    return x;

  if (x->tag == IXS_RAT)
    return ixs_node_int(ctx, ixs_rat_ceil(x->u.rat.p, x->u.rat.q));

  if (x->tag == IXS_FLOOR || x->tag == IXS_CEIL)
    return x;

  if (ixs_node_is_integer_valued(x))
    return x;

  /* ceiling(x + n) where n is integer → ceiling(x) + n */
  if (x->tag == IXS_ADD && x->u.add.coeff->tag == IXS_INT &&
      x->u.add.coeff->u.ival != 0) {
    int64_t n = x->u.add.coeff->u.ival;
    ixs_node *zero = ixs_node_int(ctx, 0);
    if (!zero)
      return NULL;
    ixs_node *inner;
    if (x->u.add.nterms == 1) {
      int64_t cp, cq;
      ixs_node_get_rat(x->u.add.terms[0].coeff, &cp, &cq);
      if (ixs_rat_is_one(cp, cq))
        inner = x->u.add.terms[0].term;
      else
        inner = ixs_node_add(ctx, zero, x->u.add.nterms, x->u.add.terms);
    } else {
      inner = ixs_node_add(ctx, zero, x->u.add.nterms, x->u.add.terms);
    }
    if (!inner)
      return NULL;
    return simp_add(ctx, simp_ceil(ctx, inner), ixs_node_int(ctx, n));
  }

  /* ceiling(ceiling(y)/b) → ceiling(y/b) for positive integer b. */
  if (x->tag == IXS_MUL && x->u.mul.nfactors == 1 &&
      x->u.mul.factors[0].exp == 1 &&
      x->u.mul.factors[0].base->tag == IXS_CEIL) {
    int64_t cp, cq;
    ixs_node_get_rat(x->u.mul.coeff, &cp, &cq);
    if (cp == 1 && cq > 1) {
      ixs_node *inner_arg = x->u.mul.factors[0].base->u.unary.arg;
      ixs_node *scaled = simp_mul(ctx, x->u.mul.coeff, inner_arg);
      if (!scaled)
        return NULL;
      return simp_ceil(ctx, scaled);
    }
  }

  return ixs_node_ceil(ctx, x);
}

/* ------------------------------------------------------------------ */
/*  simp_mod                                                          */
/* ------------------------------------------------------------------ */

ixs_node *simp_mod(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  if (!a || !b)
    return NULL;
  ixs_node *prop = ixs_propagate2(a, b);
  if (prop)
    return prop;

  /* Mod(x, 0) → error */
  if (ixs_node_is_zero(b)) {
    ixs_ctx_push_error(ctx, "Mod: divisor is zero");
    return ctx->sentinel_error;
  }

  /* Mod(c1, c2) → constant fold */
  if (ixs_node_is_const(a) && ixs_node_is_const(b)) {
    int64_t ap, aq, bp, bq, rp, rq;
    ixs_node_get_rat(a, &ap, &aq);
    ixs_node_get_rat(b, &bp, &bq);
    if (ixs_rat_is_neg(bp)) {
      ixs_ctx_push_error(ctx, "Mod: divisor is negative");
      return ctx->sentinel_error;
    }
    if (!ixs_rat_mod(ap, aq, bp, bq, &rp, &rq)) {
      ixs_ctx_push_error(ctx, "rational overflow in Mod");
      return ctx->sentinel_error;
    }
    return make_const(ctx, rp, rq);
  }

  /* Mod(x, 1) → 0 when x is known integer-valued. */
  if (ixs_node_is_one(b) && ixs_node_is_integer_valued(a))
    return ixs_node_int(ctx, 0);

  /* Mod(c*t, m) → 0 when t is integer-valued and m divides c.
   * Catches Mod(a*floor(x/a), a) and similar. */
  if (a->tag == IXS_MUL && b->tag == IXS_INT && b->u.ival > 0) {
    int64_t cp, cq;
    ixs_node_get_rat(a->u.mul.coeff, &cp, &cq);
    if (cq == 1 && cp != 0 && cp % b->u.ival == 0) {
      uint32_t i;
      bool all_int = true;
      for (i = 0; i < a->u.mul.nfactors; i++) {
        if (a->u.mul.factors[i].exp < 0 ||
            !ixs_node_is_integer_valued(a->u.mul.factors[i].base)) {
          all_int = false;
          break;
        }
      }
      if (all_int)
        return ixs_node_int(ctx, 0);
    }
  }

  /* Mod(Mod(x, m), m) → Mod(x, m) */
  if (a->tag == IXS_MOD && a->u.binary.rhs == b)
    return a;

  /* Mod(x + k*m, m) → Mod(x, m) when b is a constant integer.
   * Look for multiples of m in the additive terms of a. */
  if (a->tag == IXS_ADD && b->tag == IXS_INT && b->u.ival > 0) {
    int64_t m = b->u.ival;
    int64_t const_p, const_q;
    ixs_node_get_rat(a->u.add.coeff, &const_p, &const_q);

    /* Reduce the constant term mod m. */
    int64_t new_const_p = const_p, new_const_q = const_q;
    if (const_q == 1) {
      new_const_p = const_p % m;
      if (new_const_p < 0)
        new_const_p += m;
    }

    /* Check each term: if coefficient is a multiple of m, drop it. */
    ixs_addterm reduced[MAX_TERMS];
    uint32_t nr = 0;
    uint32_t i;
    bool changed = (new_const_p != const_p || new_const_q != const_q);

    for (i = 0; i < a->u.add.nterms; i++) {
      int64_t cp, cq;
      ixs_node_get_rat(a->u.add.terms[i].coeff, &cp, &cq);
      /* Drop ci*ti when ci is a multiple of m AND ti is integer-valued,
       * so that ci*ti is always a multiple of m. */
      if (cq == 1 && cp % m == 0 &&
          ixs_node_is_integer_valued(a->u.add.terms[i].term)) {
        changed = true;
        continue;
      }
      reduced[nr++] = a->u.add.terms[i];
    }

    if (changed) {
      ixs_node *new_a;
      if (nr == 0) {
        new_a = make_const(ctx, new_const_p, new_const_q);
      } else {
        ixs_node *c = make_const(ctx, new_const_p, new_const_q);
        if (!c)
          return NULL;
        if (nr == 1 && ixs_rat_is_zero(new_const_p)) {
          int64_t rcp, rcq;
          ixs_node_get_rat(reduced[0].coeff, &rcp, &rcq);
          if (ixs_rat_is_one(rcp, rcq))
            new_a = reduced[0].term;
          else
            new_a = simp_mul(ctx, make_const(ctx, rcp, rcq), reduced[0].term);
        } else {
          new_a = ixs_node_add(ctx, c, nr, reduced);
        }
      }
      if (!new_a)
        return NULL;
      return simp_mod(ctx, new_a, b);
    }
  }

  /* Extract a small constant addend from Mod when every other term's
   * coefficient divides the modulus.  Corrected from the Wave compiler:
   * use gcd(|ci|) not min(|ci|) for the bound on the extractable constant.
   *
   *   Mod(4*floor(a) + 3, 16)  →  Mod(4*floor(a), 16) + 3
   *
   * Proof: each |ci| | q, so sum = Σ ci*ti is a multiple of g = gcd(|ci|).
   * Then (sum mod q) ∈ {0, g, 2g, ..., q-g}.  If 0 < c < g, then
   * (sum mod q) + c < q, so Mod(sum + c, q) = (sum mod q) + c. */
  if (a->tag == IXS_ADD && b->tag == IXS_INT && b->u.ival > 0) {
    int64_t m = b->u.ival;
    int64_t const_p, const_q;
    ixs_node_get_rat(a->u.add.coeff, &const_p, &const_q);

    if (const_q == 1 && const_p > 0 && a->u.add.nterms > 0) {
      int64_t g = 0;
      bool ok = true;
      uint32_t i;

      for (i = 0; i < a->u.add.nterms; i++) {
        int64_t cp, cq;
        ixs_node_get_rat(a->u.add.terms[i].coeff, &cp, &cq);
        int64_t acp = (cp > 0) ? cp : (cp >= -INT64_MAX) ? -cp : 0;
        if (cq != 1 || acp == 0 || m % acp != 0 ||
            !ixs_node_is_integer_valued(a->u.add.terms[i].term)) {
          ok = false;
          break;
        }
        g = (g == 0) ? acp : ixs_gcd(g, acp);
      }

      if (ok && g > 1 && const_p < g) {
        ixs_node *zero = ixs_node_int(ctx, 0);
        if (!zero)
          return NULL;
        ixs_node *inner =
            ixs_node_add(ctx, zero, a->u.add.nterms, a->u.add.terms);
        if (!inner)
          return NULL;
        ixs_node *moded = simp_mod(ctx, inner, b);
        if (!moded)
          return NULL;
        return simp_add(ctx, moded, ixs_node_int(ctx, const_p));
      }
    }
  }

  return ixs_node_binary(ctx, IXS_MOD, a, b, (ixs_cmp_op)0);
}

/* ------------------------------------------------------------------ */
/*  simp_max / simp_min                                               */
/* ------------------------------------------------------------------ */

ixs_node *simp_max(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  if (!a || !b)
    return NULL;
  ixs_node *prop = ixs_propagate2(a, b);
  if (prop)
    return prop;

  if (a == b)
    return a;

  if (ixs_node_is_const(a) && ixs_node_is_const(b)) {
    int64_t ap, aq, bp, bq;
    ixs_node_get_rat(a, &ap, &aq);
    ixs_node_get_rat(b, &bp, &bq);
    return ixs_rat_cmp(ap, aq, bp, bq) >= 0 ? a : b;
  }

  /* Canonical ordering: put smaller node on left. */
  if (ixs_node_cmp(a, b) > 0)
    return ixs_node_binary(ctx, IXS_MAX, b, a, (ixs_cmp_op)0);

  return ixs_node_binary(ctx, IXS_MAX, a, b, (ixs_cmp_op)0);
}

ixs_node *simp_min(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  if (!a || !b)
    return NULL;
  ixs_node *prop = ixs_propagate2(a, b);
  if (prop)
    return prop;

  if (a == b)
    return a;

  if (ixs_node_is_const(a) && ixs_node_is_const(b)) {
    int64_t ap, aq, bp, bq;
    ixs_node_get_rat(a, &ap, &aq);
    ixs_node_get_rat(b, &bp, &bq);
    return ixs_rat_cmp(ap, aq, bp, bq) <= 0 ? a : b;
  }

  if (ixs_node_cmp(a, b) > 0)
    return ixs_node_binary(ctx, IXS_MIN, b, a, (ixs_cmp_op)0);

  return ixs_node_binary(ctx, IXS_MIN, a, b, (ixs_cmp_op)0);
}

/* ------------------------------------------------------------------ */
/*  simp_xor                                                          */
/* ------------------------------------------------------------------ */

ixs_node *simp_xor(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  if (!a || !b)
    return NULL;
  ixs_node *prop = ixs_propagate2(a, b);
  if (prop)
    return prop;

  if (a == b)
    return ixs_node_int(ctx, 0);
  if (ixs_node_is_zero(a))
    return b;
  if (ixs_node_is_zero(b))
    return a;

  if (a->tag == IXS_INT && b->tag == IXS_INT)
    return ixs_node_int(ctx, a->u.ival ^ b->u.ival);

  if (ixs_node_cmp(a, b) > 0)
    return ixs_node_binary(ctx, IXS_XOR, b, a, (ixs_cmp_op)0);

  return ixs_node_binary(ctx, IXS_XOR, a, b, (ixs_cmp_op)0);
}

/* ------------------------------------------------------------------ */
/*  simp_cmp                                                          */
/* ------------------------------------------------------------------ */

ixs_node *simp_cmp(ixs_ctx *ctx, ixs_node *a, ixs_cmp_op op, ixs_node *b) {
  if (!a || !b)
    return NULL;
  ixs_node *prop = ixs_propagate2(a, b);
  if (prop)
    return prop;

  /* Constant fold */
  if (ixs_node_is_const(a) && ixs_node_is_const(b)) {
    int64_t ap, aq, bp, bq;
    ixs_node_get_rat(a, &ap, &aq);
    ixs_node_get_rat(b, &bp, &bq);
    int c = ixs_rat_cmp(ap, aq, bp, bq);
    bool result = false;
    switch (op) {
    case IXS_CMP_GT:
      result = c > 0;
      break;
    case IXS_CMP_GE:
      result = c >= 0;
      break;
    case IXS_CMP_LT:
      result = c < 0;
      break;
    case IXS_CMP_LE:
      result = c <= 0;
      break;
    case IXS_CMP_EQ:
      result = c == 0;
      break;
    case IXS_CMP_NE:
      result = c != 0;
      break;
    }
    return result ? ctx->node_true : ctx->node_false;
  }

  /* a op a → fold */
  if (a == b) {
    switch (op) {
    case IXS_CMP_GE:
    case IXS_CMP_LE:
    case IXS_CMP_EQ:
      return ctx->node_true;
    case IXS_CMP_GT:
    case IXS_CMP_LT:
    case IXS_CMP_NE:
      return ctx->node_false;
    }
  }

  /* Normalize: (a op b) → ((a - b) op 0) */
  if (!ixs_node_is_zero(b)) {
    ixs_node *diff = simp_sub(ctx, a, b);
    if (!diff)
      return NULL;
    if (ixs_node_is_sentinel(diff))
      return diff;
    return simp_cmp(ctx, diff, op, ixs_node_int(ctx, 0));
  }

  return ixs_node_binary(ctx, IXS_CMP, a, b, op);
}

/* ------------------------------------------------------------------ */
/*  simp_and / simp_or / simp_not                                     */
/* ------------------------------------------------------------------ */

ixs_node *simp_not(ixs_ctx *ctx, ixs_node *a) {
  ixs_node *prop = ixs_propagate1(a);
  if (prop)
    return prop;

  if (a->tag == IXS_TRUE)
    return ctx->node_false;
  if (a->tag == IXS_FALSE)
    return ctx->node_true;

  /* ~~x → x */
  if (a->tag == IXS_NOT)
    return a->u.unary_bool.arg;

  /* ~(a > b) → a <= b, etc. */
  if (a->tag == IXS_CMP) {
    ixs_cmp_op flipped;
    switch (a->u.binary.cmp_op) {
    case IXS_CMP_GT:
      flipped = IXS_CMP_LE;
      break;
    case IXS_CMP_GE:
      flipped = IXS_CMP_LT;
      break;
    case IXS_CMP_LT:
      flipped = IXS_CMP_GE;
      break;
    case IXS_CMP_LE:
      flipped = IXS_CMP_GT;
      break;
    case IXS_CMP_EQ:
      flipped = IXS_CMP_NE;
      break;
    case IXS_CMP_NE:
      flipped = IXS_CMP_EQ;
      break;
    default:
      flipped = a->u.binary.cmp_op;
      break;
    }
    return ixs_node_binary(ctx, IXS_CMP, a->u.binary.lhs, a->u.binary.rhs,
                           flipped);
  }

  return ixs_node_not(ctx, a);
}

ixs_node *simp_and(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  if (!a || !b)
    return NULL;
  ixs_node *prop = ixs_propagate2(a, b);
  if (prop)
    return prop;

  if (a->tag == IXS_FALSE || b->tag == IXS_FALSE)
    return ctx->node_false;
  if (a->tag == IXS_TRUE)
    return b;
  if (b->tag == IXS_TRUE)
    return a;
  if (a == b)
    return a;

  /* Flatten n-ary AND. */
  ixs_node *args[MAX_TERMS];
  uint32_t nargs = 0;
  uint32_t i;

  ixs_node *inputs[2];
  inputs[0] = a;
  inputs[1] = b;

  for (i = 0; i < 2; i++) {
    ixs_node *x = inputs[i];
    if (x->tag == IXS_AND) {
      uint32_t j;
      for (j = 0; j < x->u.logic.nargs && nargs < MAX_TERMS; j++)
        args[nargs++] = x->u.logic.args[j];
    } else {
      if (nargs < MAX_TERMS)
        args[nargs++] = x;
    }
  }

  /* Sort and deduplicate. */
  qsort(args, nargs, sizeof(ixs_node *), nodeptr_cmp);
  {
    uint32_t j2 = 0;
    for (i = 0; i < nargs; i++) {
      if (j2 > 0 && args[j2 - 1] == args[i])
        continue;
      args[j2++] = args[i];
    }
    nargs = j2;
  }

  if (nargs == 1)
    return args[0];

  return ixs_node_logic(ctx, IXS_AND, nargs, args);
}

ixs_node *simp_or(ixs_ctx *ctx, ixs_node *a, ixs_node *b) {
  if (!a || !b)
    return NULL;
  ixs_node *prop = ixs_propagate2(a, b);
  if (prop)
    return prop;

  if (a->tag == IXS_TRUE || b->tag == IXS_TRUE)
    return ctx->node_true;
  if (a->tag == IXS_FALSE)
    return b;
  if (b->tag == IXS_FALSE)
    return a;
  if (a == b)
    return a;

  ixs_node *args[MAX_TERMS];
  uint32_t nargs = 0;
  uint32_t i;

  ixs_node *inputs[2];
  inputs[0] = a;
  inputs[1] = b;

  for (i = 0; i < 2; i++) {
    ixs_node *x = inputs[i];
    if (x->tag == IXS_OR) {
      uint32_t j;
      for (j = 0; j < x->u.logic.nargs && nargs < MAX_TERMS; j++)
        args[nargs++] = x->u.logic.args[j];
    } else {
      if (nargs < MAX_TERMS)
        args[nargs++] = x;
    }
  }

  qsort(args, nargs, sizeof(ixs_node *), nodeptr_cmp);
  {
    uint32_t j2 = 0;
    for (i = 0; i < nargs; i++) {
      if (j2 > 0 && args[j2 - 1] == args[i])
        continue;
      args[j2++] = args[i];
    }
    nargs = j2;
  }

  if (nargs == 1)
    return args[0];

  return ixs_node_logic(ctx, IXS_OR, nargs, args);
}

/* ------------------------------------------------------------------ */
/*  simp_pw (Piecewise)                                               */
/* ------------------------------------------------------------------ */

ixs_node *simp_pw(ixs_ctx *ctx, uint32_t n, ixs_node **values,
                  ixs_node **conds) {
  ixs_pwcase cases[MAX_TERMS];
  uint32_t ncases = 0;
  uint32_t i;

  if (n == 0) {
    ixs_ctx_push_error(ctx, "Piecewise: zero cases");
    return ctx->sentinel_error;
  }

  for (i = 0; i < n; i++) {
    ixs_node *v = values[i];
    ixs_node *c = conds[i];

    if (!v || !c)
      return NULL;

    /* Drop branches with False condition. */
    if (c->tag == IXS_FALSE)
      continue;

    /* Sentinel in condition of reachable branch. */
    if (ixs_node_is_sentinel(c)) {
      /* If there's a preceding True branch, this is unreachable. */
      if (ncases > 0 && cases[ncases - 1].cond->tag == IXS_TRUE)
        continue;
      return c;
    }

    /* True condition: this is the final branch. */
    if (c->tag == IXS_TRUE) {
      if (ixs_node_is_sentinel(v)) {
        /* Sentinel in catch-all value: check if there were earlier
         * branches that cover all cases. */
        if (ncases > 0 && cases[ncases - 1].cond->tag == IXS_TRUE)
          break;
        return v;
      }
      cases[ncases].value = v;
      cases[ncases].cond = c;
      ncases++;
      break;
    }

    /* Merge adjacent cases with same value. */
    if (ncases > 0 && cases[ncases - 1].value == v) {
      cases[ncases - 1].cond = simp_or(ctx, cases[ncases - 1].cond, c);
      if (!cases[ncases - 1].cond)
        return NULL;
      continue;
    }

    cases[ncases].value = v;
    cases[ncases].cond = c;
    ncases++;
  }

  if (ncases == 0) {
    ixs_ctx_push_error(ctx, "Piecewise: all conditions are False");
    return ctx->sentinel_error;
  }

  /* Single branch with True → just return value. */
  if (ncases == 1 && cases[0].cond->tag == IXS_TRUE)
    return cases[0].value;

  return ixs_node_pw(ctx, ncases, cases);
}

/* ------------------------------------------------------------------ */
/*  simp_subs (substitution with memoization)                         */
/* ------------------------------------------------------------------ */

#define SUBS_MEMO_SIZE 256u
#define SUBS_MEMO_MASK (SUBS_MEMO_SIZE - 1u)

typedef struct {
  ixs_node *key;
  ixs_node *val;
} subs_memo_slot;

static size_t subs_memo_idx(ixs_node *n) {
  uint32_t h = n->hash;
  return (size_t)((h ^ (h >> 8)) & SUBS_MEMO_MASK);
}

static ixs_node *subs_rec(ixs_ctx *ctx, ixs_node *expr, ixs_node *target,
                          ixs_node *replacement, subs_memo_slot *memo) {
  uint32_t i;
  size_t slot;
  ixs_node *result;

  if (!expr)
    return NULL;
  if (ixs_node_is_sentinel(expr))
    return expr;

  if (expr == target)
    return replacement;

  switch (expr->tag) {
  case IXS_INT:
  case IXS_RAT:
  case IXS_SYM:
  case IXS_TRUE:
  case IXS_FALSE:
  case IXS_ERROR:
  case IXS_PARSE_ERROR:
    return expr;
  default:
    break;
  }

  slot = subs_memo_idx(expr);
  if (memo[slot].key == expr)
    return memo[slot].val;

  result = NULL;

  switch (expr->tag) {
  case IXS_ADD: {
    ixs_node *nc = subs_rec(ctx, expr->u.add.coeff, target, replacement, memo);
    if (!nc)
      return NULL;
    result = nc;
    for (i = 0; i < expr->u.add.nterms; i++) {
      ixs_node *nt =
          subs_rec(ctx, expr->u.add.terms[i].term, target, replacement, memo);
      if (!nt)
        return NULL;
      ixs_node *ncoeff =
          subs_rec(ctx, expr->u.add.terms[i].coeff, target, replacement, memo);
      if (!ncoeff)
        return NULL;
      ixs_node *term = simp_mul(ctx, ncoeff, nt);
      if (!term)
        return NULL;
      result = simp_add(ctx, result, term);
      if (!result)
        return NULL;
    }
    break;
  }
  case IXS_MUL: {
    ixs_node *nc = subs_rec(ctx, expr->u.mul.coeff, target, replacement, memo);
    if (!nc)
      return NULL;
    result = nc;
    for (i = 0; i < expr->u.mul.nfactors; i++) {
      ixs_node *nb =
          subs_rec(ctx, expr->u.mul.factors[i].base, target, replacement, memo);
      if (!nb)
        return NULL;
      int32_t e = expr->u.mul.factors[i].exp;
      ixs_node *power;
      if (e == 1) {
        power = nb;
      } else {
        ixs_mulfactor f;
        f.base = nb;
        f.exp = e;
        power = ixs_node_mul(ctx, ixs_node_int(ctx, 1), 1, &f);
      }
      if (!power)
        return NULL;
      result = simp_mul(ctx, result, power);
      if (!result)
        return NULL;
    }
    break;
  }
  case IXS_FLOOR: {
    ixs_node *na = subs_rec(ctx, expr->u.unary.arg, target, replacement, memo);
    result = na ? simp_floor(ctx, na) : NULL;
    break;
  }
  case IXS_CEIL: {
    ixs_node *na = subs_rec(ctx, expr->u.unary.arg, target, replacement, memo);
    result = na ? simp_ceil(ctx, na) : NULL;
    break;
  }
  case IXS_MOD:
  case IXS_MAX:
  case IXS_MIN:
  case IXS_XOR: {
    ixs_node *nl = subs_rec(ctx, expr->u.binary.lhs, target, replacement, memo);
    ixs_node *nr = subs_rec(ctx, expr->u.binary.rhs, target, replacement, memo);
    if (!nl || !nr)
      return NULL;
    switch (expr->tag) {
    case IXS_MOD:
      result = simp_mod(ctx, nl, nr);
      break;
    case IXS_MAX:
      result = simp_max(ctx, nl, nr);
      break;
    case IXS_MIN:
      result = simp_min(ctx, nl, nr);
      break;
    case IXS_XOR:
      result = simp_xor(ctx, nl, nr);
      break;
    default:
      break;
    }
    break;
  }
  case IXS_CMP: {
    ixs_node *nl = subs_rec(ctx, expr->u.binary.lhs, target, replacement, memo);
    ixs_node *nr = subs_rec(ctx, expr->u.binary.rhs, target, replacement, memo);
    if (!nl || !nr)
      return NULL;
    result = simp_cmp(ctx, nl, expr->u.binary.cmp_op, nr);
    break;
  }
  case IXS_PIECEWISE: {
    ixs_node *vals[MAX_TERMS], *cds[MAX_TERMS];
    if (expr->u.pw.ncases > MAX_TERMS)
      return NULL;
    for (i = 0; i < expr->u.pw.ncases; i++) {
      vals[i] =
          subs_rec(ctx, expr->u.pw.cases[i].value, target, replacement, memo);
      cds[i] =
          subs_rec(ctx, expr->u.pw.cases[i].cond, target, replacement, memo);
      if (!vals[i] || !cds[i])
        return NULL;
    }
    result = simp_pw(ctx, expr->u.pw.ncases, vals, cds);
    break;
  }
  case IXS_AND: {
    result = ctx->node_true;
    for (i = 0; i < expr->u.logic.nargs; i++) {
      ixs_node *na =
          subs_rec(ctx, expr->u.logic.args[i], target, replacement, memo);
      if (!na)
        return NULL;
      result = simp_and(ctx, result, na);
      if (!result)
        return NULL;
    }
    break;
  }
  case IXS_OR: {
    result = ctx->node_false;
    for (i = 0; i < expr->u.logic.nargs; i++) {
      ixs_node *na =
          subs_rec(ctx, expr->u.logic.args[i], target, replacement, memo);
      if (!na)
        return NULL;
      result = simp_or(ctx, result, na);
      if (!result)
        return NULL;
    }
    break;
  }
  case IXS_NOT: {
    ixs_node *na =
        subs_rec(ctx, expr->u.unary_bool.arg, target, replacement, memo);
    result = na ? simp_not(ctx, na) : NULL;
    break;
  }
  default:
    result = expr;
    break;
  }

  if (result) {
    memo[slot].key = expr;
    memo[slot].val = result;
  }
  return result;
}

ixs_node *simp_subs(ixs_ctx *ctx, ixs_node *expr, ixs_node *target,
                    ixs_node *replacement) {
  subs_memo_slot memo[SUBS_MEMO_SIZE];

  if (!expr)
    return NULL;
  if (ixs_node_is_sentinel(expr))
    return expr;
  if (!target || !replacement)
    return NULL;
  if (expr == target)
    return replacement;

  memset(memo, 0, sizeof(memo));
  return subs_rec(ctx, expr, target, replacement, memo);
}

/* ------------------------------------------------------------------ */
/*  simp_simplify (top-down with assumptions)                         */
/* ------------------------------------------------------------------ */

/* Forward decl for recursive rewrite. */
static ixs_node *rewrite(ixs_ctx *ctx, ixs_node *n, ixs_bounds *bnds);

/* Collapse floor or ceil to a constant when bounds pin it to one value.
 * Returns the constant node, or NULL if bounds don't collapse. */
static ixs_node *try_floor_ceil_collapse(ixs_ctx *ctx, ixs_bounds *bnds,
                                         ixs_node *arg, bool is_ceil) {
  ixs_interval iv;
  int64_t lo_val, hi_val;
  if (!bnds)
    return NULL;
  iv = ixs_bounds_get(bnds, arg);
  if (!iv.valid)
    return NULL;
  lo_val = is_ceil ? ixs_rat_ceil(iv.lo_p, iv.lo_q)
                   : ixs_rat_floor(iv.lo_p, iv.lo_q);
  hi_val = is_ceil ? ixs_rat_ceil(iv.hi_p, iv.hi_q)
                   : ixs_rat_floor(iv.hi_p, iv.hi_q);
  if (lo_val == hi_val)
    return ixs_node_int(ctx, lo_val);
  return NULL;
}

/* True when expr is provably divisible by m (m > 0) given bounds.
 * Handles: sym with known divisor, c*sym, sums of divisible terms. */
static bool is_known_divisible(ixs_bounds *bnds, ixs_node *expr, int64_t m) {
  if (!bnds || m <= 0)
    return false;

  /* Integer constant: m | val */
  if (expr->tag == IXS_INT)
    return expr->u.ival % m == 0;

  /* Symbol with known divisor d: m | d */
  if (expr->tag == IXS_SYM) {
    int64_t d = ixs_bounds_get_divisor(bnds, expr->u.name);
    return d > 0 && d % m == 0;
  }

  /* c * base^1: m | (c * divisor(base)) when c is integer */
  if (expr->tag == IXS_MUL && expr->u.mul.nfactors == 1 &&
      expr->u.mul.factors[0].exp == 1 && expr->u.mul.coeff->tag == IXS_INT) {
    int64_t c = expr->u.mul.coeff->u.ival;
    if (c == 0)
      return true;
    int64_t g = ixs_gcd(c, m);
    int64_t remain = m / g;
    return is_known_divisible(bnds, expr->u.mul.factors[0].base, remain);
  }

  /* ADD: every term c_i * t_i must be divisible by m, and the constant
   * term must also be divisible by m. */
  if (expr->tag == IXS_ADD) {
    int64_t cp, cq;
    uint32_t i;
    ixs_node_get_rat(expr->u.add.coeff, &cp, &cq);
    if (cq != 1 || cp % m != 0)
      return false;
    for (i = 0; i < expr->u.add.nterms; i++) {
      int64_t tp, tq;
      ixs_node_get_rat(expr->u.add.terms[i].coeff, &tp, &tq);
      if (tq != 1)
        return false;
      int64_t g = ixs_gcd(tp, m);
      int64_t remain = m / g;
      if (!is_known_divisible(bnds, expr->u.add.terms[i].term, remain))
        return false;
    }
    return true;
  }

  return false;
}

/* True when expr is provably integer-valued given divisibility info.
 * Extends ixs_node_is_integer_valued with divisibility reasoning:
 * p/q * sym is integer when q divides the known divisor of sym. */
static bool is_integer_with_divinfo(ixs_bounds *bnds, ixs_node *expr) {
  if (ixs_node_is_integer_valued(expr))
    return true;
  if (!bnds)
    return false;

  /* MUL: p/q * base^1 is integer if base's divisor absorbs q */
  if (expr->tag == IXS_MUL && expr->u.mul.nfactors == 1 &&
      expr->u.mul.factors[0].exp == 1) {
    int64_t cp, cq;
    ixs_node_get_rat(expr->u.mul.coeff, &cp, &cq);
    if (cq <= 1)
      return true;
    int64_t g = ixs_gcd(cp, cq);
    int64_t denom = cq / g;
    return is_known_divisible(bnds, expr->u.mul.factors[0].base, denom);
  }

  /* ADD: integer coeff + all integer-valued terms */
  if (expr->tag == IXS_ADD) {
    uint32_t i;
    if (!is_integer_with_divinfo(bnds, expr->u.add.coeff))
      return false;
    for (i = 0; i < expr->u.add.nterms; i++) {
      int64_t cp, cq;
      ixs_node_get_rat(expr->u.add.terms[i].coeff, &cp, &cq);
      if (cq == 1) {
        if (!is_integer_with_divinfo(bnds, expr->u.add.terms[i].term))
          return false;
      } else {
        /* c_i/q_i * t_i: integer if t_i divisible by q_i/gcd(|c_i|,q_i) */
        int64_t g = ixs_gcd(cp, cq);
        int64_t denom = cq / g;
        if (!is_known_divisible(bnds, expr->u.add.terms[i].term, denom))
          return false;
      }
    }
    return true;
  }

  return false;
}

static ixs_node *rewrite(ixs_ctx *ctx, ixs_node *n, ixs_bounds *bnds) {
  uint32_t i;
  if (!n || ixs_node_is_sentinel(n))
    return n;

  switch (n->tag) {
  case IXS_INT:
  case IXS_RAT:
  case IXS_SYM:
  case IXS_TRUE:
  case IXS_FALSE:
  case IXS_ERROR:
  case IXS_PARSE_ERROR:
    return n;

  case IXS_ADD: {
    ixs_node *result = rewrite(ctx, n->u.add.coeff, bnds);
    if (!result)
      return NULL;
    for (i = 0; i < n->u.add.nterms; i++) {
      ixs_node *t = rewrite(ctx, n->u.add.terms[i].term, bnds);
      if (!t)
        return NULL;
      ixs_node *c = n->u.add.terms[i].coeff;
      result = simp_add(ctx, result, simp_mul(ctx, c, t));
      if (!result)
        return NULL;
    }
    return result;
  }
  case IXS_MUL: {
    ixs_node *result = rewrite(ctx, n->u.mul.coeff, bnds);
    if (!result)
      return NULL;
    for (i = 0; i < n->u.mul.nfactors; i++) {
      ixs_node *b = rewrite(ctx, n->u.mul.factors[i].base, bnds);
      if (!b)
        return NULL;
      ixs_mulfactor f;
      f.base = b;
      f.exp = n->u.mul.factors[i].exp;
      ixs_node *pw = ixs_node_mul(ctx, ixs_node_int(ctx, 1), 1, &f);
      if (!pw)
        return NULL;
      result = simp_mul(ctx, result, pw);
      if (!result)
        return NULL;
    }
    return result;
  }
  case IXS_FLOOR: {
    ixs_node *arg = rewrite(ctx, n->u.unary.arg, bnds);
    if (!arg)
      return NULL;

    if (bnds) {
      ixs_node *collapsed = try_floor_ceil_collapse(ctx, bnds, arg, false);
      if (collapsed)
        return collapsed;

      /* floor(x) → x when x is provably integer via divisibility */
      if (is_integer_with_divinfo(bnds, arg))
        return arg;

      /* Drop a small rational constant from floor's argument when every
       * term is a non-negative-integer-valued multiple of 1/qi.
       *
       *   floor(floor(a)/3 + 1/6)  →  floor(floor(a)/3)
       *
       * Each ti/qi has fractional part in {0, 1/L, ..., (L-1)/L} where
       * L = lcm(qi).  If 0 < r < 1/L, adding r can't cross an integer
       * boundary, so floor(sum + r) = floor(sum). */
      if (arg->tag == IXS_ADD && arg->u.add.coeff->tag == IXS_RAT &&
          arg->u.add.nterms > 0) {
        int64_t rp = arg->u.add.coeff->u.rat.p;
        int64_t rq = arg->u.add.coeff->u.rat.q;

        if (rp > 0 && rq > 1) {
          int64_t L = 1;
          bool ok = true;
          uint32_t j;

          for (j = 0; j < arg->u.add.nterms; j++) {
            int64_t cp, cq;
            ixs_node_get_rat(arg->u.add.terms[j].coeff, &cp, &cq);
            if (cq <= 1) {
              ok = false;
              break;
            }
            if (!ixs_node_is_integer_valued(arg->u.add.terms[j].term)) {
              ok = false;
              break;
            }
            ixs_interval ti = ixs_bounds_get(bnds, arg->u.add.terms[j].term);
            if (!ti.valid || ti.lo_q != 1 || ti.lo_p < 0) {
              ok = false;
              break;
            }
            int64_t g = ixs_gcd(L, cq);
            if (g == 0 || L > INT64_MAX / (cq / g)) {
              ok = false;
              break;
            }
            L = L / g * cq;
          }

          /* r < 1/L  ⟺  rp * L < rq  (since rp, rq, L > 0) */
          if (ok && L > 0 && rp <= INT64_MAX / L && rp * L < rq) {
            ixs_node *zero = ixs_node_int(ctx, 0);
            if (!zero)
              return NULL;
            ixs_node *inner =
                ixs_node_add(ctx, zero, arg->u.add.nterms, arg->u.add.terms);
            if (!inner)
              return NULL;
            return simp_floor(ctx, inner);
          }
        }
      }
    }
    return simp_floor(ctx, arg);
  }
  case IXS_CEIL: {
    ixs_node *arg = rewrite(ctx, n->u.unary.arg, bnds);
    if (!arg)
      return NULL;

    if (bnds) {
      ixs_node *collapsed = try_floor_ceil_collapse(ctx, bnds, arg, true);
      if (collapsed)
        return collapsed;

      /* ceil(x) → x when x is provably integer via divisibility */
      if (is_integer_with_divinfo(bnds, arg))
        return arg;
    }
    return simp_ceil(ctx, arg);
  }
  case IXS_MOD: {
    ixs_node *l = rewrite(ctx, n->u.binary.lhs, bnds);
    ixs_node *r = rewrite(ctx, n->u.binary.rhs, bnds);
    if (!l || !r)
      return NULL;

    if (bnds && r->tag == IXS_INT && r->u.ival > 0) {
      /* Mod(x, m) where 0 <= x < m → x */
      ixs_interval iv = ixs_bounds_get(bnds, l);
      if (iv.valid && iv.lo_q == 1 && iv.hi_q == 1 && iv.lo_p >= 0 &&
          iv.hi_p < r->u.ival)
        return l;

      /* Mod(x, m) → 0 when x is known divisible by m */
      if (is_known_divisible(bnds, l, r->u.ival))
        return ixs_node_int(ctx, 0);
    }
    return simp_mod(ctx, l, r);
  }
  case IXS_MAX: {
    ixs_node *l = rewrite(ctx, n->u.binary.lhs, bnds);
    ixs_node *r = rewrite(ctx, n->u.binary.rhs, bnds);
    if (!l || !r)
      return NULL;

    if (bnds) {
      ixs_interval il = ixs_bounds_get(bnds, l);
      ixs_interval ir = ixs_bounds_get(bnds, r);
      /* If lo(l) >= hi(r), l is always >= r. */
      if (il.valid && ir.valid) {
        if (ixs_rat_cmp(il.lo_p, il.lo_q, ir.hi_p, ir.hi_q) >= 0)
          return l;
        if (ixs_rat_cmp(ir.lo_p, ir.lo_q, il.hi_p, il.hi_q) >= 0)
          return r;
      }
    }
    return simp_max(ctx, l, r);
  }
  case IXS_MIN: {
    ixs_node *l = rewrite(ctx, n->u.binary.lhs, bnds);
    ixs_node *r = rewrite(ctx, n->u.binary.rhs, bnds);
    if (!l || !r)
      return NULL;
    if (bnds) {
      ixs_interval il = ixs_bounds_get(bnds, l);
      ixs_interval ir = ixs_bounds_get(bnds, r);
      if (il.valid && ir.valid) {
        if (ixs_rat_cmp(il.hi_p, il.hi_q, ir.lo_p, ir.lo_q) <= 0)
          return l;
        if (ixs_rat_cmp(ir.hi_p, ir.hi_q, il.lo_p, il.lo_q) <= 0)
          return r;
      }
    }
    return simp_min(ctx, l, r);
  }
  case IXS_XOR: {
    ixs_node *l = rewrite(ctx, n->u.binary.lhs, bnds);
    ixs_node *r = rewrite(ctx, n->u.binary.rhs, bnds);
    return (l && r) ? simp_xor(ctx, l, r) : NULL;
  }
  case IXS_CMP: {
    ixs_node *l = rewrite(ctx, n->u.binary.lhs, bnds);
    ixs_node *r = rewrite(ctx, n->u.binary.rhs, bnds);
    if (!l || !r)
      return NULL;
    ixs_node *result = simp_cmp(ctx, l, n->u.binary.cmp_op, r);

    /* Bound-dependent: if diff = l - r is normalized to (expr cmp 0),
     * try to resolve using bounds. */
    if (result && result->tag == IXS_CMP && bnds &&
        ixs_node_is_zero(result->u.binary.rhs)) {
      ixs_interval iv = ixs_bounds_get(bnds, result->u.binary.lhs);
      if (iv.valid) {
        bool known = false;
        bool val = false;
        switch (result->u.binary.cmp_op) {
        case IXS_CMP_GT:
          if (ixs_rat_cmp(iv.lo_p, iv.lo_q, 0, 1) > 0) {
            known = true;
            val = true;
          } else if (ixs_rat_cmp(iv.hi_p, iv.hi_q, 0, 1) <= 0) {
            known = true;
            val = false;
          }
          break;
        case IXS_CMP_GE:
          if (ixs_rat_cmp(iv.lo_p, iv.lo_q, 0, 1) >= 0) {
            known = true;
            val = true;
          } else if (ixs_rat_cmp(iv.hi_p, iv.hi_q, 0, 1) < 0) {
            known = true;
            val = false;
          }
          break;
        case IXS_CMP_LT:
          if (ixs_rat_cmp(iv.hi_p, iv.hi_q, 0, 1) < 0) {
            known = true;
            val = true;
          } else if (ixs_rat_cmp(iv.lo_p, iv.lo_q, 0, 1) >= 0) {
            known = true;
            val = false;
          }
          break;
        case IXS_CMP_LE:
          if (ixs_rat_cmp(iv.hi_p, iv.hi_q, 0, 1) <= 0) {
            known = true;
            val = true;
          } else if (ixs_rat_cmp(iv.lo_p, iv.lo_q, 0, 1) > 0) {
            known = true;
            val = false;
          }
          break;
        case IXS_CMP_EQ:
          if (ixs_rat_cmp(iv.lo_p, iv.lo_q, 0, 1) == 0 &&
              ixs_rat_cmp(iv.hi_p, iv.hi_q, 0, 1) == 0) {
            known = true;
            val = true;
          } else if (ixs_rat_cmp(iv.lo_p, iv.lo_q, 0, 1) > 0 ||
                     ixs_rat_cmp(iv.hi_p, iv.hi_q, 0, 1) < 0) {
            known = true;
            val = false;
          }
          break;
        case IXS_CMP_NE:
          if (ixs_rat_cmp(iv.lo_p, iv.lo_q, 0, 1) > 0 ||
              ixs_rat_cmp(iv.hi_p, iv.hi_q, 0, 1) < 0) {
            known = true;
            val = true;
          }
          break;
        }
        if (known)
          return val ? ctx->node_true : ctx->node_false;
      }
    }
    return result;
  }
  case IXS_PIECEWISE: {
    ixs_node *vals[MAX_TERMS], *cds[MAX_TERMS];
    if (n->u.pw.ncases > MAX_TERMS)
      return NULL;
    for (i = 0; i < n->u.pw.ncases; i++) {
      vals[i] = rewrite(ctx, n->u.pw.cases[i].value, bnds);
      cds[i] = rewrite(ctx, n->u.pw.cases[i].cond, bnds);
      if (!vals[i] || !cds[i])
        return NULL;
    }
    return simp_pw(ctx, n->u.pw.ncases, vals, cds);
  }
  case IXS_AND: {
    ixs_node *result = ctx->node_true;
    for (i = 0; i < n->u.logic.nargs; i++) {
      ixs_node *a = rewrite(ctx, n->u.logic.args[i], bnds);
      if (!a)
        return NULL;
      result = simp_and(ctx, result, a);
      if (!result)
        return NULL;
    }
    return result;
  }
  case IXS_OR: {
    ixs_node *result = ctx->node_false;
    for (i = 0; i < n->u.logic.nargs; i++) {
      ixs_node *a = rewrite(ctx, n->u.logic.args[i], bnds);
      if (!a)
        return NULL;
      result = simp_or(ctx, result, a);
      if (!result)
        return NULL;
    }
    return result;
  }
  case IXS_NOT: {
    ixs_node *a = rewrite(ctx, n->u.unary_bool.arg, bnds);
    return a ? simp_not(ctx, a) : NULL;
  }
  }
  return n;
}

ixs_node *simp_simplify(ixs_ctx *ctx, ixs_node *expr,
                        ixs_node *const *assumptions, size_t n_assumptions) {
  int iter;
  if (!expr)
    return NULL;
  if (ixs_node_is_sentinel(expr))
    return expr;

  ixs_bounds bnds;
  ixs_bounds_init(&bnds);

  /* Extract bounds from assumptions. */
  if (assumptions) {
    size_t i;
    for (i = 0; i < n_assumptions; i++) {
      ixs_node *a = assumptions[i];
      if (!a || ixs_node_is_sentinel(a))
        continue;
      ixs_bounds_add_assumption(&bnds, a);
    }
  }

  /* Fixed-point iteration. */
  for (iter = 0; iter < SIMPLIFY_ITER_LIMIT; iter++) {
    ixs_node *prev = expr;
    expr = rewrite(ctx, expr, &bnds);
    if (!expr)
      return NULL;
    if (expr == prev)
      break;
  }

  if (iter == SIMPLIFY_ITER_LIMIT)
    ixs_ctx_push_error(ctx, "simplify: iteration limit reached");

  ixs_bounds_destroy(&bnds);
  return expr;
}
